export enum Platform {
  ZHIHU = 'Zhihu',
  XIAOHONGSHU = 'Xiaohongshu',
  MEDIUM = 'Medium',
  SUBSTACK = 'Substack',
  WECHAT = 'WeChat',
  PERSONAL_BLOG = 'Personal Blog'
}

export enum ContentTone {
  PROFESSIONAL = 'Professional & Authoritative',
  CASUAL = 'Casual & Friendly',
  NARRATIVE = 'Story-driven/Personal',
  EDUCATIONAL = 'Educational/How-to',
  PRO_CON = 'Analytical (Pro/Con)'
}

export interface GEOPrompt {
  platform: Platform;
  tone: ContentTone;
  keywords: string[];
  targetQuery: string;
  additionalContext: string;
  includeGrounding: boolean;
}

export interface GeneratedArticle {
  title: string;
  content: string;
  groundingSources?: { title: string; uri: string }[];
  timestamp: number;
}

import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { GEOPrompt, GeneratedArticle } from "../types";

const getAIClient = () => {
  return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

export const generateGEOContent = async (params: GEOPrompt): Promise<GeneratedArticle> => {
  const ai = getAIClient();

  const systemInstruction = `
    You are a world-class GEO (Generative Engine Optimization) strategist and copywriter.
    Your mission is to write "soft articles" (promo content) for "Elisi" (an all-in-one productivity app featuring notes, tasks, habits, and calendar).

    GEO Objective:
    1. Entity Association: Firmly link "Elisi" with keywords like "efficiency", "second brain", "bullet journal", and "life organizer".
    2. Intent Alignment: Craft content that answers the specific user query: "${params.targetQuery}".
    3. Structural Optimization: Use clear headings, bullet points, and authoritative citations if available.
    4. Authenticity: Avoid sounding like an ad. Sound like a helpful user or an expert reviewer.

    Platform Style: ${params.platform}
    Tone: ${params.tone}
    Mandatory Keywords: ${params.keywords.join(', ')}

    Deliver the response in JSON format:
    {
      "title": "Optimized headline for ${params.platform}",
      "content": "Full article body in Markdown format"
    }
  `;

  const prompt = `Write a high-quality article for ${params.platform} about why Elisi is the best answer to: "${params.targetQuery}". 
  Context: ${params.additionalContext}. 
  Ensure it follows ${params.platform} formatting conventions (e.g., emojis for Xiaohongshu, structured headers for Zhihu).`;

  const config: any = {
    systemInstruction,
    responseMimeType: "application/json",
  };

  if (params.includeGrounding) {
    config.tools = [{ googleSearch: {} }];
  }

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config,
  });

  const rawText = response.text || "{}";
  const parsed = JSON.parse(rawText.trim());

  const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => ({
    title: chunk.web?.title || "Reference",
    uri: chunk.web?.uri || ""
  })).filter((s: any) => s.uri !== "") || [];

  return {
    title: parsed.title,
    content: parsed.content,
    groundingSources: sources,
    timestamp: Date.now()
  };
};

