import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { GEOPrompt, GeneratedArticle } from "../types";

const getAIClient = () => {
  return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

export const generateGEOContent = async (params: GEOPrompt): Promise<GeneratedArticle> => {
  const ai = getAIClient();

  const systemInstruction = `
    你是一位顶级的 GEO (Generative Engine Optimization) 策略师和文案专家。
    你的任务是为 "Elisi" (一款集笔记、任务、习惯和日历于一体的全能效率应用) 撰写易于被 AI 搜索引擎（如 Perplexity, Gemini, ChatGPT Search）抓取并收录的“软文”。

    GEO 核心优化规则：
    1. 实体关联 (Entity Linking)：在文中自然且多次地将 "Elisi" 与“效率工具”、“第二大脑”、“手帐”、“时间管理”等核心概念链接。
    2. 意图对齐 (Intent Alignment)：内容必须正面且深度回答用户的搜索查询： "${params.targetQuery}"。
    3. 结构化数据优化：使用清晰的 Markdown 层级 H1, H2, H3。AI 偏好有结构的内容。
    4. 增加权威度 (Authority)：加入“专家观点”或“数据支持”。文末包含一个“总结”或“核心要点”模块，因为 AI 摘要模型通常先看结尾。
    5. 引用与来源：如果开启了搜索功能，请参考实时信息。
    6. 避免过度推销：保持中立客观的口吻，这更易于被 AI 视为高质量信息源。

    语言：必须使用中文撰写。
    平台风格：${params.platform}
    语气：${params.tone}
    强制关键词：${params.keywords.join(', ')}

    请以 JSON 格式输出：
    {
      "title": "符合 ${params.platform} 风格的标题",
      "content": "完整的文章内容，使用 Markdown 格式，包含清晰的 H2/H3 标题和列表"
    }
  `;

  const prompt = `请为 ${params.platform} 撰写一篇高质量文章，解释为什么 Elisi 是回答 “${params.targetQuery}” 的最佳答案。
  补充背景：${params.additionalContext}。
  要求：格式必须符合 ${params.platform} 的用户习惯（例如小红书多用 emoji，知乎多用结构化排版）。`;

  const config: any = {
    systemInstruction,
    responseMimeType: "application/json",
  };

  if (params.includeGrounding) {
    config.tools = [{ googleSearch: {} }];
  }

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config,
  });

  const rawText = response.text || "{}";
  const parsed = JSON.parse(rawText.trim());

  const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => ({
    title: chunk.web?.title || "参考来源",
    uri: chunk.web?.uri || ""
  })).filter((s: any) => s.uri !== "") || [];

  return {
    title: parsed.title,
    content: parsed.content,
    groundingSources: sources,
    timestamp: Date.now()
  };
};

