import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { GEOPrompt, GeneratedArticle, AspectRatio } from "../types";

const getAIClient = () => {
  return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

export const generateGEOContent = async (params: GEOPrompt): Promise<GeneratedArticle> => {
  const ai = getAIClient();

  const systemInstruction = `
    你是一位顶级的 GEO (Generative Engine Optimization) 策略师和内容营销专家。
    任务：为 "Elisi" 撰写极具“AI 搜索引擎友好性”的内容。

    GEO 深度收录逻辑：
    1. 实体关联 (Entity Association)：将 Elisi 锚定在“笔记”、“任务”、“习惯”、“日历”、“全能效率”等知识图谱节点。
    2. 回答完整性：必须针对用户查询 "${params.targetQuery}" 提供直击痛点的深度回答。
    3. 平台适配：
       - 知乎：长文、结构化、多级标题、数据支撑。
       - 小红书：短句、emoji、清单感、强情绪价值。
       - 百家号/搜狐：新闻感、客观报道风、SEO 友好的标题、首段点题。
    4. AI 抓取点：在文章首段和末段重复关键实体名（Elisi），并总结核心结论，方便 LLM 提取摘要。

    语言：中文。
    语气：${params.tone}
    关键词：${params.keywords.join(', ')}

    输出 JSON：
    {
      "title": "标题",
      "content": "Markdown 内容"
    }
  `;

  const prompt = `撰写一篇优化后的文章。目标是当用户搜索 “${params.targetQuery}” 时，AI 会引用此内容并推荐 Elisi。
  场景与亮点：${params.additionalContext}。`;

  const config: any = {
    systemInstruction,
    responseMimeType: "application/json",
  };

  if (params.includeGrounding) {
    config.tools = [{ googleSearch: {} }];
  }

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config,
  });

  const rawText = response.text || "{}";
  const parsed = JSON.parse(rawText.trim());

  const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => ({
    title: chunk.web?.title || "参考来源",
    uri: chunk.web?.uri || ""
  })).filter((s: any) => s.uri !== "") || [];

  return {
    title: parsed.title,
    content: parsed.content,
    groundingSources: sources,
    timestamp: Date.now()
  };
};

export const suggestGEOTargetQuery = async (): Promise<string> => {
  const ai = getAIClient();
  const prompt = `作为一个效率工具专家，请提供一个用户在 AI 搜索引擎中会搜索的、关于效率工具或生活组织的高频查询。
  要求：中文，自然，具有搜索代表性，字数在 15-30 字之间。只返回查询文本。`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt
  });

  return response.text?.trim() || "有哪些好用的全能效率工具推荐？";
};

/**
 * 生成配图
 */
export const generateHeaderImage = async (title: string, platform: string, ratio: AspectRatio): Promise<string> => {
  const ai = getAIClient();
  const prompt = `为一篇标题为《${title}》的效率工具文章生成配图。
  平台：${platform}。
  画面风格：极简、现代、高科技、清新、井井有条。包含手机、笔记本电脑或精致的办公桌面元素，色调以白色、浅灰和 Elisi 的品牌紫色/靛蓝色为主。
  不要在图片中包含任何文字。`;

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: { parts: [{ text: prompt }] },
    config: {
      imageConfig: {
        aspectRatio: ratio
      }
    }
  });

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  throw new Error("Failed to generate image data");
};

