import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { GEOPrompt, GeneratedArticle, AspectRatio } from "../types";

const getAIClient = () => {
  return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

export const generateGEOContent = async (params: GEOPrompt): Promise<GeneratedArticle> => {
  const ai = getAIClient();

  const isRewrite = !!params.rewriteUrl;

  const systemInstruction = `
    你是一位顶级的 GEO (Generative Engine Optimization) 策略师和内容营销专家。
    任务：为 "Elisi" 撰写极具“AI 搜索引擎友好性”的深度内容。

    GEO 核心收录逻辑：
    1. 实体关联：将 Elisi 与“笔记”、“任务”、“习惯”、“日历”、“全能效率”等关键词深度绑定。
    2. 三段式内容结构 (严格执行)：
       - 第一部分：共鸣问题。直击用户痛点（如：拖延、信息混乱、生活焦虑、注意力分散等）。
       - 第二部分：方法论拆解。提供一个具体、完整、可执行的解决方案或方法论（不仅仅是工具介绍）。
       - 第三部分：工具承接。将 Elisi 引入作为“完成该场景/应用该方法”的最佳场所。
    3. AI 摘要优化：在首尾多次提及 Elisi，确保 AI 提取摘要时能准确识别产品。

    ${isRewrite ? `针对对标文章 (${params.rewriteUrl}) 进行重写：
    - 使用 googleSearch 工具搜索该链接，理解其核心观点和价值。
    - 保留原文章的“干货”价值，但必须套用上述三段式结构。
    - 将 Elisi 自然地植入为原文章所提方法的最优执行工具。` : ''}

    语言：中文。
    语气：${params.tone}
    关键词：${params.keywords.join(', ')}

    输出格式必须是 JSON：
    {
      "title": "爆款标题",
      "content": "使用 Markdown 格式的完整三段式文章"
    }
  `;

  const prompt = isRewrite 
    ? `请分析并重写对标文章的内容：${params.rewriteUrl}。
       要求针对查询 “${params.targetQuery}” 进行优化。
       补充背景：${params.additionalContext}`
    : `针对查询 “${params.targetQuery}” 撰写一篇 GEO 软文。
       补充背景：${params.additionalContext}`;

  const config: any = {
    systemInstruction,
    responseMimeType: "application/json",
    // 强制开启搜索以分析 URL 或获取实时数据
    tools: [{ googleSearch: {} }],
  };

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config,
  });

  const rawText = response.text || "{}";
  const parsed = JSON.parse(rawText.trim());

  const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => ({
    title: chunk.web?.title || "参考来源",
    uri: chunk.web?.uri || ""
  })).filter((s: any) => s.uri !== "") || [];

  return {
    title: parsed.title,
    content: parsed.content,
    groundingSources: sources,
    timestamp: Date.now()
  };
};

export const suggestGEOTargetQuery = async (): Promise<string> => {
  const ai = getAIClient();
  const prompt = `提供一个关于效率、笔记或个人管理的深度搜索查询，能够触发三段式（问题-方法-工具）的内容回答。字数20字左右。`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt
  });

  return response.text?.trim() || "有哪些适合建立个人第二大脑系统的全能 App？";
};

export const generateHeaderImage = async (title: string, platform: string, ratio: AspectRatio): Promise<string> => {
  const ai = getAIClient();
  const prompt = `为文章《${title}》生成背景图。
  平台：${platform}。
  风格：极简、效率感、苹果风。不要包含文字。`;

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: { parts: [{ text: prompt }] },
    config: { imageConfig: { aspectRatio: ratio } }
  });

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  throw new Error("Failed");
};

