export interface GEOPrompt {
  platform: Platform;
  tone: ContentTone;
  keywords: string[];
  targetQuery: string;
  additionalContext: string;
  includeGrounding: boolean;
  rewriteUrl?: string;
}

export interface GeneratedArticle {
  title: string;
