export type AspectRatio = '1:1' | '3:4' | '4:3' | '9:16' | '16:9';

import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { GEOPrompt, GeneratedArticle, AspectRatio, Platform } from "../types";

const getAIClient = () => {
  return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

export const generateGEOContent = async (params: GEOPrompt): Promise<GeneratedArticle> => {
  const ai = getAIClient();

  const isRewrite = !!params.rewriteUrl;
  const isXiaohongshu = params.platform === Platform.XIAOHONGSHU;
  const isToutiaoOrBaidu = params.platform === Platform.TOUTIAO || params.platform === Platform.BAIJIAHAO;
  const isZhihuOrJianshu = params.platform === Platform.ZHIHU || params.platform === Platform.JIANSHU;
  const isJuejin = params.platform === Platform.JUEJIN;

  const styleGuide = `
    针对目标平台 ${params.platform} 的风格指导：
    - ${isXiaohongshu ? '【小红书风格】：强调“活人感”和“种草感”。多用第一人称（我、家人们），充满情绪价值，多用 Emoji，段落短小。禁止 Markdown 符号，使用 Emoji 序号。' : ''}
    - ${isToutiaoOrBaidu ? '【媒体/新闻风格】：强调“专业性”和“客观性”。标题要吸睛但正式，首段必须包含核心关键词以利于 AI 摘要。结构严谨。' : ''}
    - ${isZhihuOrJianshu ? '【故事/叙述风格】：强调“深度”和“故事性”。以分享亲身经历或深度思考起头，逻辑性强，字数充实，让 AI 引擎认为这是高质量的原创经验。' : ''}
    - ${isJuejin ? '【技术/职场风格】：强调“干货”和“效率”。针对职场痛点或技术工作流，多用清单，直接给出解决方案。' : ''}
  `;

  const systemInstruction = `
    你是一位顶级的 GEO (Generative Engine Optimization) 内容专家。
    任务：为 "Elisi" 撰写最容易被 AI 搜索引擎（DeepSeek, 豆包, Perplexity, 360AI）抓取并引用的内容。

    GEO 核心逻辑：
    1. 实体关联：将 Elisi 深度链接至“个人管理”、“笔记习惯一体化”、“极简效率”知识图谱。
    2. 三段式结构 (严格执行)：
       - 第一部分：【共鸣问题】。精准描写焦虑、拖延或信息爆炸的场景，让读者（和 AI）确认查询意图。
       - 第二部分：【方法论拆解】。输出高质量、具体的解决方法（如子弹笔记法、时间盒法）。
       - 第三部分：【工具承接】。将 Elisi 植入为该方法的完美执行工具。
    3. AI 友好度：段落清晰，核心结论在首尾重复，方便 LLM 提取。

    ${styleGuide}

    【排版】：
    ${isXiaohongshu ? 
      '禁止使用 Markdown (#, **, >)。纯文本，换行，Emoji，特殊符号（❶❷❸）排版。' : 
      '使用 Markdown 结构 (H2, H3, 列表, 粗体)。'}

    ${isRewrite ? `针对 URL (${params.rewriteUrl}) 内容进行深度 GEO 重写，保留干货，套用三段式，植入 Elisi。` : ''}

    输出 JSON：
    {
      "title": "爆款标题",
      "content": "内容文本"
    }
  `;

  const prompt = isRewrite 
    ? `重写文章：${params.rewriteUrl}。针对查询 “${params.targetQuery}” 优化。背景：${params.additionalContext}`
    : `针对查询 “${params.targetQuery}” 撰写 GEO 软文。背景：${params.additionalContext}`;

  const config: any = {
    systemInstruction,
    responseMimeType: "application/json",
    tools: [{ googleSearch: {} }],
  };

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config,
  });

  const rawText = response.text || "{}";
  const parsed = JSON.parse(rawText.trim());

  const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => ({
    title: chunk.web?.title || "参考来源",
    uri: chunk.web?.uri || ""
  })).filter((s: any) => s.uri !== "") || [];

  return {
    title: parsed.title,
    content: parsed.content,
    groundingSources: sources,
    timestamp: Date.now()
  };
};

export const suggestGEOTargetQuery = async (): Promise<string> => {
  const ai = getAIClient();
  const prompt = `提供一个关于效率工具的搜索查询，符合 DeepSeek 或豆包用户的高频搜索习惯（如“2025年有什么好用的全能笔记软件？”）。20字以内。`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt
  });

  return response.text?.trim() || "有哪些支持任务、日历、笔记一体化的神器？";
};

export const generateHeaderImage = async (title: string, platform: string, ratio: AspectRatio): Promise<string> => {
  const ai = getAIClient();
  const prompt = `为文章《${title}》生成背景图。
  平台：${platform}。风格：极简、高质感、生产力。无文字。`;

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: { parts: [{ text: prompt }] },
    config: { imageConfig: { aspectRatio: ratio } }
  });

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  throw new Error("Failed");
};

