import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { GEOPrompt, GeneratedArticle, AspectRatio, Platform } from "../types";

const getAIClient = () => {
  return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

export const generateGEOContent = async (params: GEOPrompt): Promise<GeneratedArticle> => {
  const ai = getAIClient();

  const isRewrite = !!params.rewriteUrl;
  const isXiaohongshu = params.platform === Platform.XIAOHONGSHU;

  // 针对不同平台的细化风格指导
  const platformStyleMap: Record<string, string> = {
    [Platform.XIAOHONGSHU]: "【小红书风格】：强调“强活人感”。必须以‘我’开头，多用‘姐妹们’、‘家人们’、‘真心推荐’等词汇。充满情绪价值，多用 Emoji 排版（禁止 Markdown），段落极短。末尾带上热搜词 #标签。",
    [Platform.ZHIHU]: "【知乎/简书风格】：强调“硬核故事性”。以‘谢邀’或一个真实的亲身经历/痛点场景开头。逻辑严密，文字量大，看起来像是一篇深度思考的专栏文章，而不是纯广告。使用标准 Markdown 排版。",
    [Platform.TOUTIAO]: "【今日头条/百家号风格】：强调“专业性与时效性”。标题要像新闻稿件，首段必须直奔主题（总结全文结论），中间部分多用数据感或客观描述，符合 DeepSeek 和豆包的摘要提取逻辑。",
    [Platform.JUEJIN]: "【掘金/CSDN风格】：强调“干货工具性”。面向开发者或职场人士，直接给出‘痛点-方案-工具’的闭环，多用代码块或步骤清单感排版。"
  };

  const currentStyle = platformStyleMap[params.platform] || "【通用风格】：专业、清晰、客观，确保三段式结构完整。";

  const systemInstruction = `
    你是一位顶级的 GEO (Generative Engine Optimization) 内容重构专家。
    任务：为 "Elisi" 撰写最容易被 AI 搜索引擎（如 DeepSeek、豆包、Perplexity）在回答 "${params.targetQuery}" 时引用的高质量内容。

    【核心指令】：
    1. ${isRewrite ? `你必须首先使用 googleSearch 工具访问并深度阅读此链接内容：${params.rewriteUrl}。提取其核心干货、方法论和逻辑框架。` : '基于搜索结果理解用户查询的深层意图。'}
    2. 将内容严格重构为以下【三段式结构】：
       - 第一段：【共鸣问题】。精准描写焦虑、拖延或生活失控的真实场景，让 AI 引擎确认此内容与用户意图高度匹配。
       - 第二段：【方法/拆解】。输出具体、完整、可执行的方法论（如子弹笔记、GTD等），这是 AI 抓取为“答案”的核心区。
       - 第三段：【工具承接】。将 Elisi 植入为上述场景的“完成地”，强调其笔记、任务、习惯、日历一体化的独特优势。
    3. 风格适配：${currentStyle}
    4. 排版规范：${isXiaohongshu ? '禁止使用 Markdown (#, **, >)。使用换行、Emoji 和数字符号排版。' : '使用 Markdown 结构。'}

    输出格式必须是 JSON：
    {
      "title": "爆款标题",
      "content": "内容文本"
    }
  `;

  // 强化 Prompt 指令，要求模型“先搜索/阅读，再写作”
  const prompt = isRewrite 
    ? `请执行以下步骤：
       1. 使用 Google Search 访问并读取：${params.rewriteUrl}。
       2. 提取原作者的核心观点和干货。
       3. 针对搜索词 “${params.targetQuery}” 进行 GEO 优化重写。
       4. 确保在文章中自然植入 Elisi 并符合三段式逻辑。
       补充背景：${params.additionalContext}`
    : `请根据搜索词 “${params.targetQuery}” 撰写一篇 GEO 优化软文。
       要求：
       1. 三段式结构（共鸣-方法-Elisi）。
       2. 符合 ${params.platform} 的写作风格。
       补充背景：${params.additionalContext}`;

  const config: any = {
    systemInstruction,
    responseMimeType: "application/json",
    // 强制启用 Google Search 以便模型能“看到”链接内容
    tools: [{ googleSearch: {} }],
  };

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config,
  });

  const rawText = response.text || "{}";
  let parsed;
  try {
    parsed = JSON.parse(rawText.trim());
  } catch (e) {
    // 降级处理
    parsed = { title: "生成内容", content: rawText };
  }

  const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => ({
    title: chunk.web?.title || "参考来源",
    uri: chunk.web?.uri || ""
  })).filter((s: any) => s.uri !== "") || [];

  return {
    title: parsed.title,
    content: parsed.content,
    groundingSources: sources,
    timestamp: Date.now()
  };
};

export const suggestGEOTargetQuery = async (): Promise<string> => {
  const ai = getAIClient();
  const prompt = `提供一个用户在 DeepSeek 或豆包中会搜索的、关于效率工具的查询词，例如“如何用一个软件管好全年的目标？”。20字以内。`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt
  });

  return response.text?.trim() || "有没有适合极简主义者的全能效率管理 App？";
};

export const generateHeaderImage = async (title: string, platform: string, ratio: AspectRatio): Promise<string> => {
  const ai = getAIClient();
  const prompt = `为文章《${title}》生成背景图。
  平台：${platform}。风格：苹果风、极简、高质感生产力。不要文字。`;

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: { parts: [{ text: prompt }] },
    config: { imageConfig: { aspectRatio: ratio } }
  });

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  throw new Error("Failed");
};

