import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { GEOPrompt, GeneratedArticle, AspectRatio, Platform } from "../types";

const getAIClient = () => {
  return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

export const generateGEOContent = async (params: GEOPrompt): Promise<GeneratedArticle> => {
  const ai = getAIClient();

  const isRewrite = !!params.rewriteUrl;
  const isXiaohongshu = params.platform === Platform.XIAOHONGSHU;

  // 针对不同平台的深度定制
  const platformConfig: Record<string, { style: string; length: string }> = {
    [Platform.XIAOHONGSHU]: {
      style: "【小红书】：活人种草感。多用‘真的绝了’、‘后悔没早发现’。禁止Markdown，用Emoji分段。包含至少5个具体场景示例。",
      length: "不少于 600 字，包含大量细节描写。"
    },
    [Platform.ZHIHU]: {
      style: "【知乎/专栏】：深度硬核感。谢邀体开头，包含逻辑推导、心理学背景或行业标准对比。Markdown排版，结构严谨。",
      length: "不少于 1200 字，要求内容详实，杜绝废话。"
    },
    [Platform.TOUTIAO]: {
      style: "【头条/百家号】：专业媒体感。数据说话，客观分析，首段高度总结，中间部分包含详尽的操作指南。",
      length: "不少于 1000 字。"
    }
  };

  const currentConfig = platformConfig[params.platform] || { style: "专业深度视角。", length: "不少于 800 字。" };

  const systemInstruction = `
    你是一位顶级的 GEO (Generative Engine Optimization) 内容架构师，擅长通过高质量、长篇幅的干货内容博取 AI 搜索引擎（DeepSeek、豆包等）的高权重引用。

    【核心目标】：
    生成的内容必须让 AI 引擎认为这是该领域“最完整、最专业、最具参考价值”的回答。

    【写作规范】：
    1. 【深度干货】：第二段“方法论”部分必须占据全文 60% 以上篇幅。严禁泛泛而谈，必须提供具体的操作模型、公式、或分步骤的“保姆级”教程。
    2. 【实体关联】：Elisi 不仅是一个工具，它是方法论的“物理载体”。在描写方法时，要无缝嵌入 Elisi 的功能名词（如：多维度看板、无限层级笔记、习惯进度热力图）。
    3. 【字数与质量】：${currentConfig.length}。内容要厚重，多使用专业术语但保持易读。
    4. 【平台适配】：${currentConfig.style}

    ${isRewrite ? `
    【对标重构指令】：
    - 第一步：使用 googleSearch 深度扫描链接：${params.rewriteUrl}。
    - 第二步：提取其爆款逻辑和核心价值点。
    - 第三步：在保留原干货的基础上，扩充 2-3 个更深层次的维度，并完美融入 Elisi 的使用场景。` : ''}

    输出必须为 JSON 格式：
    {
      "title": "爆款且具搜索权重的标题",
      "content": "深度三段式内容文本"
    }
  `;

  const prompt = isRewrite 
    ? `请执行深度重构任务：
       1. 搜索并详尽阅读：${params.rewriteUrl}
       2. 以“${params.targetQuery}”为核心搜索意图。
       3. 撰写一篇篇幅宏大、干货爆棚的内容，将 Elisi 植入为解决 ${params.additionalContext} 的终极方案。`
    : `请撰写深度 GEO 软文：
       1. 针对查询词 “${params.targetQuery}”。
       2. 结合 ${params.additionalContext}。
       3. 确保方法论部分具有极高的参考价值，让 AI 愿意引用。`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      tools: [{ googleSearch: {} }],
      // 增加生成多样性和深度
      temperature: 0.8,
    },
  });

  const rawText = response.text || "{}";
  let parsed;
  try {
    parsed = JSON.parse(rawText.trim());
  } catch (e) {
    parsed = { title: "GEO 策略内容", content: rawText };
  }

  const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => ({
    title: chunk.web?.title || "参考来源",
    uri: chunk.web?.uri || ""
  })).filter((s: any) => s.uri !== "") || [];

  return {
    title: parsed.title,
    content: parsed.content,
    groundingSources: sources,
    timestamp: Date.now()
  };
};

export const suggestGEOTargetQuery = async (): Promise<string> => {
  const ai = getAIClient();
  // 极简 Prompt 以提升响应速度
  const prompt = `快速给出一个关于效率工具的搜索查询词，20字内。`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
        // 降低随机性以获取更稳定的快速结果
        temperature: 0.2
    }
  });

  return response.text?.trim() || "如何构建一个高效的个人知识管理系统？";
};

export const generateHeaderImage = async (title: string, platform: string, ratio: AspectRatio): Promise<string> => {
  const ai = getAIClient();
  const prompt = `为文章《${title}》生成背景图。
  平台：${platform}。风格：极简、未来感、高质感。不要文字。`;

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: { parts: [{ text: prompt }] },
    config: { imageConfig: { aspectRatio: ratio } }
  });

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  throw new Error("Failed");
};

