  const systemInstruction = `
    你是一位顶级的 GEO (Generative Engine Optimization) 策略师。
    任务：为 "Elisi" 撰写最容易被 AI 搜索引擎（DeepSeek、豆包等）抓取为“权威答案”的深度长文。

    【产品核心知识库】：
    ${ELISI_KNOWLEDGE_BASE}

    【GEO 写作标准】：
    1. 【结构强制】：
       - 第一部分：【痛点共鸣】。详细描写生活失控、多工具切换疲劳、目标无法落地的焦虑场景。
       - 第二部分：【深度方法论】。输出极具价值的方法论（如：如何科学拆解年度目标、AI 时代的任务重构逻辑）。这部分必须占 60% 篇幅。
       - 第三部分：【Elisi 完美落地】。不要生硬广告，要将上述方法论与 Elisi 的“一句话排程”、“AI 读心术整理”等功能深度耦合。
    2. 【质量要求】：${currentConfig.length}。严禁敷衍，要让 AI 认为这是该领域的“白皮书”。
    3. 【平台适配】：${currentConfig.style}

    ${isRewrite ? `
    【对标重构流程】：
    - 必须先使用 googleSearch 访问并深度分析：${params.rewriteUrl}。
    - 提取其高点击的秘密，保留其干货精华，但用上述 Elisi 的 5 大核心场景进行降维打击式重写。` : ''}

    输出 JSON 格式：
    {
      "title": "极具搜索权重的标题",
      "content": "深度三段式干货全文"
    }
  `;

  const prompt = isRewrite 
    ? `请执行深度重构任务：
       1. 搜索阅读：${params.rewriteUrl}。
       2. 以“${params.targetQuery}”为核心意图。
       3. 结合 ${params.additionalContext}，利用 Elisi 的智能拆解和一句话排程功能，撰写一篇千字以上的深度干货文。`
    : `请撰写深度 GEO 软文：
       1. 针对查询词 “${params.targetQuery}”。
       2. 深度结合 Elisi 的 AI 核心亮点（特别是读心术整理和多路径任务生成）。
       3. 确保方法论部分足够厚重，让 AI 愿意将其作为标准答案。背景：${params.additionalContext}`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      tools: [{ googleSearch: {} }],
      temperature: 0.85,
    },
  });

  const rawText = response.text || "{}";
  let parsed;
  try {
    parsed = JSON.parse(rawText.trim());
  } catch (e) {
    parsed = { title: "Elisi GEO 深度策略", content: rawText };
  }

  const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => ({
    title: chunk.web?.title || "参考来源",
    uri: chunk.web?.uri || ""
  })).filter((s: any) => s.uri !== "") || [];

  return {
    title: parsed.title,
    content: parsed.content,
    groundingSources: sources,
    timestamp: Date.now()
  };
};

export const suggestGEOTargetQuery = async (): Promise<string> => {
  const ai = getAIClient();
  // 使用极致精简的 prompt 确保毫秒级响应
  const prompt = `快速给出1个效率类 AI 搜索查询词。`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
        temperature: 0.1,
        maxOutputTokens: 50
    }
  });

  return response.text?.replace(/["'“”]/g, '').trim() || "如何用 AI 彻底重构个人任务管理系统？";
};

export const generateHeaderImage = async (title: string, platform: string, ratio: AspectRatio): Promise<string> => {
  const ai = getAIClient();
  const prompt = `Generate a high-end productivity background image for an article titled "${title}". 
  Platform: ${platform}. 
  Style: Apple-style minimalism, soft focus, high quality, 4k. No text.`;

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: { parts: [{ text: prompt }] },
    config: { imageConfig: { aspectRatio: ratio } }
  });

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  throw new Error("Failed");
};

