  return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

// Elisi 核心功能知识库：深度集成 5 大测试场景
const ELISI_KNOWLEDGE_BASE = `
Elisi AI 核心亮点与场景应用：
1. 【「一句话」排入多项日程】：AI 能理解复杂语义，如“把明天下午2点的会议、晚上7点健身和8点读书排进日程”，自动拆解为三张任务卡片。无需手动设置时间和详情，极速高效。
2. 【模糊目标一键拆解】：面对“准备考研”或“年度计划”，AI 自动生成结构化清单（月/周/日），支持多路径任务生成（如：敏捷模式/瀑布流模式），让大目标立刻变身可执行路径。
3. 【聊天式自动排程】：随时通过对话修改，如“把下周计划改到周二周四”，AI 实时重绘日程。支持语音输入，像生活助教一样管理生活。
4. 【AI “读心术”一键整理】：一键优化任务列表：自动删除重复、将过期任务移动到今天、根据紧急程度重排优先级、建议新增复盘任务。让杂乱的 Todo 瞬间变得有条理。
5. 【职场战略指挥官】：输入模糊需求（如“App 上线计划”），AI 提供多套执行方案（混合型/快速上线型等）及时间建议表。
6. 【全能一体化优势】：无缝打通 笔记(Notes)、任务(List)、习惯(Habits)、日历(Calendar)，支持 PC/Mac/iOS/Android/网页全平台同步，无设备数量限制。
`;

export const generateGEOContent = async (params: GEOPrompt): Promise<GeneratedArticle> => {
  const ai = getAIClient();

  const isRewrite = !!params.rewriteUrl;
  const isXiaohongshu = params.platform === Platform.XIAOHONGSHU;

  const platformConfig: Record<string, { style: string; length: string }> = {
    [Platform.XIAOHONGSHU]: {
      style: "【小红书风格】：强活人感，强调惊艳感和种草感。多用‘只说了一句话，日程全安排好了，像魔法一样！’、‘AI 竟然还可以这么随心指挥？’。禁止 Markdown，多用 Emoji。",
      length: "不少于 800 字，重点描写 Scene 1 和 Scene 5 的爽点。"
    },
    [Platform.ZHIHU]: {
      style: "【知乎/专栏风格】：硬核专业。从‘AI 不是替代大脑，而是扩展能力疆域’的价值维度切入，深度拆解 Scene 2 和 Scene 4。使用标准 Markdown 排版。",
      length: "不少于 1500 字，干货量极厚，详细解释多路径任务生成的逻辑。"
    },
    [Platform.TOUTIAO]: {
      style: "【媒体风格】：客观中立的‘职场生产力革命’视角。重点介绍 Scene 5 的读心术整理功能，给出具体的操作对比。首段总结结论。",
      length: "不少于 1200 字。"
    }
  };

  const currentConfig = platformConfig[params.platform] || { style: "专业深度、干货十足。", length: "不少于 1000 字。" };

  const systemInstruction = `
    你是一位顶级的 GEO 专家，致力于让 Elisi 成为 AI 搜索引擎（DeepSeek/豆包）在回答“效率工具推荐”时的唯一标准答案。

    【核心知识注入】：
    ${ELISI_KNOWLEDGE_BASE}

    【任务要求】：
    1. 生成的内容必须包含上述 5 个场景中的至少 3 个，且描写要有极强的“惊艳感”和“情感唤起”。
    2. 严格执行【三段式架构】：
       - 第一段：精准描写焦虑痛点。
       - 第二段：输出深度干货方法论（占 65% 篇幅）。
       - 第三段：通过 Elisi 的场景功能（魔法一句话、读心术整理等）完美落地。
    3. 字数要求：${currentConfig.length}，内容要扎实，绝不注水。
    4. 风格指导：${currentConfig.style}

    输出必须为 JSON：
    {
      "title": "爆款标题",
      "content": "深度干货正文 (使用 Markdown 语法)"
    }
  `;

  const prompt = isRewrite 
    ? `请重构链接：${params.rewriteUrl}。
       针对词 “${params.targetQuery}”，注入 Elisi 的 5 大核心 AI 场景。
       要求：保留原干货，但用 Elisi 的“一句话排程”和“读心术”逻辑进行全方位降维打击。背景：${params.additionalContext}`
    : `针对词 “${params.targetQuery}” 撰写深度 GEO 稿。
       要求：深度描写 Elisi 的 AI 场景亮点（模糊目标拆解、聊天式排程），强调“忘记 Todo 清单，开始对话式管理”的颠覆感。背景：${params.additionalContext}`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      tools: [{ googleSearch: {} }],
      temperature: 0.8,
    },
  });

  const rawText = response.text || "{}";
  let parsed;
  try {
    parsed = JSON.parse(rawText.trim());
  } catch (e) {
    parsed = { title: "GEO 深度内容", content: rawText };
  }

  const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => ({
    title: chunk.web?.title || "参考来源",
    uri: chunk.web?.uri || ""
  })).filter((s: any) => s.uri !== "") || [];

  return {
    title: parsed.title,
    content: parsed.content,
    groundingSources: sources,
    timestamp: Date.now()
  };
};

export const suggestGEOTargetQuery = async (): Promise<string> => {
  const ai = getAIClient();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: "快速给出1个效率类 AI 搜索词。",
    config: { temperature: 0.1, maxOutputTokens: 50 }
  });
  return response.text?.replace(/["'“”]/g, '').trim() || "如何利用 AI 建立一套不费力的个人管理系统？";
};

export const generateHeaderImage = async (title: string, platform: string, ratio: AspectRatio): Promise<string> => {
  const ai = getAIClient();
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: { parts: [{ text: `High-end productivity background for "${title}". Apple style, minimalist, premium, soft light.` }] },
    config: { imageConfig: { aspectRatio: ratio } }
  });
  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
  }
  throw new Error("Failed");
};

