const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'generate' | 'rewrite'>('generate');
  const [viewMode, setViewMode] = useState<'rich' | 'markdown'>('rich');
  const [loading, setLoading] = useState(false);
  const [suggesting, setSuggesting] = useState(false);
  const [imageLoading, setImageLoading] = useState(false);
  const [result, setResult] = useState<GeneratedArticle | null>(null);
  const [headerImage, setHeaderImage] = useState<string | null>(null);
  const [selectedRatio, setSelectedRatio] = useState<AspectRatio>('16:9');

  const [formData, setFormData] = useState<GEOPrompt>({
    platform: Platform.ZHIHU,
    tone: ContentTone.PROFESSIONAL,
    keywords: ['Elisi', 'AI 读心术', '一句话排程', '任务自动拆解', '职场指挥官'],
    targetQuery: '2025年有什么好用的 AI 任务管理工具推荐？',
    additionalContext: '强调“忘记 Todo 清单，开始对话式管理”的效率跨越。',
    includeGrounding: true,
    rewriteUrl: ''
  });

  const htmlContent = useMemo(() => {
    if (!result) return '';
    return marked.parse(result.content);
  }, [result]);

  const handleSuggestQuery = async () => {
    if (suggesting) return;
    setSuggesting(true);
    // Visual feedback
    setFormData(prev => ({ ...prev, targetQuery: '正在预测搜索意图...' }));
    try {
      const query = await suggestGEOTargetQuery();
      setFormData(prev => ({ ...prev, targetQuery: query }));
    } catch (error) {
      console.error(error);
      setFormData(prev => ({ ...prev, targetQuery: '如何利用 AI 建立一套不费力的个人管理系统？' }));
    } finally {
      setSuggesting(false);
    }
  };

  const handleAction = async () => {
    if (activeTab === 'rewrite' && !formData.rewriteUrl) {
      alert("请输入对标文章的链接。");
      return;
    }
    setLoading(true);
    setResult(null);
    setHeaderImage(null);
    try {
      const params = { ...formData };
      if (activeTab === 'generate') params.rewriteUrl = '';
      const article = await generateGEOContent(params);
      setResult(article);
    } catch (error) {
      console.error(error);
      alert("生成失败，请稍后重试。");
    } finally {
      setLoading(false);
    }
  };

  const handleGenerateImage = async () => {
    if (!result) return;
    setImageLoading(true);
    try {
      const imgUrl = await generateHeaderImage(result.title, formData.platform, selectedRatio);
      setHeaderImage(imgUrl);
    } catch (error) {
      console.error(error);
      alert("生成配图失败。");
