                  {['1:1', '3:4', '4:3', '9:16', '16:9'].map(r => <option key={r} value={r}>{r}</option>)}
                </select>
              </div>
              <div className="aspect-video bg-slate-50 rounded-2xl overflow-hidden mb-4 border border-dashed border-slate-200 relative group">
                {headerImage ? (
                  <img src={headerImage} className="w-full h-full object-cover" />
                ) : (
                  <div className="absolute inset-0 flex flex-col items-center justify-center text-[10px] text-slate-300 font-black uppercase tracking-widest gap-2">
                    <svg className="w-6 h-6 opacity-20" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                    <span>视觉预览区</span>
                  </div>
                )}
                {imageLoading && (
                  <div className="absolute inset-0 bg-white/60 backdrop-blur-sm flex items-center justify-center">
                    <div className="flex flex-col items-center gap-2">
                      <svg className="animate-spin h-6 w-6 text-indigo-600" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" fill="none"/><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"/></svg>
                      <span className="text-[10px] font-black text-indigo-600 uppercase">渲染中</span>
                    </div>
                  </div>
                )}
              </div>
              <button 
                onClick={handleGenerateImage} 
                disabled={imageLoading || !result} 
                className="w-full py-3 bg-slate-900 text-white text-[10px] font-black uppercase rounded-xl shadow-lg hover:bg-slate-800 transition-colors disabled:opacity-50"
              >
                生成适配渠道头图
              </button>
            </div>
          </div>

          {/* Results Panel */}
          <div className="lg:col-span-8">
            {loading ? (
              <div className="bg-white rounded-[2.5rem] p-12 shadow-sm border border-slate-200 h-full min-h-[800px] flex flex-col space-y-12">
                <div className="animate-pulse space-y-8">
                  <div className="h-14 bg-slate-100 rounded-2xl w-3/4"></div>
                  <div className="space-y-4">
                    <div className="h-4 bg-slate-50 rounded w-full"></div>
                    <div className="h-4 bg-slate-50 rounded w-full"></div>
                    <div className="h-4 bg-slate-50 rounded w-11/12"></div>
                    <div className="h-4 bg-slate-50 rounded w-full"></div>
                    <div className="h-4 bg-slate-50 rounded w-10/12"></div>
                  </div>
                  <div className="h-64 bg-slate-50 rounded-3xl w-full"></div>
                  <div className="space-y-4">
                    <div className="h-4 bg-slate-50 rounded w-full"></div>
                    <div className="h-4 bg-slate-50 rounded w-full"></div>
                    <div className="h-4 bg-slate-50 rounded w-9/12"></div>
                  </div>
                </div>
              </div>
            ) : result ? (
              <div className="bg-white rounded-[2.5rem] shadow-2xl border border-slate-200 overflow-hidden h-full flex flex-col min-h-[800px]">
                <div className="bg-slate-950 text-white px-8 py-5 flex flex-wrap justify-between items-center gap-4">
                  <div className="flex bg-white/10 p-1 rounded-xl">
                    <button 
                      onClick={() => setViewMode('rich')} 
                      className={`text-[10px] font-black uppercase px-5 py-2 rounded-lg transition-all ${viewMode === 'rich' ? 'bg-white text-slate-900' : 'text-slate-400 hover:text-white'}`}
                    >
                      富文本
                    </button>
                    <button 
                      onClick={() => setViewMode('markdown')} 
                      className={`text-[10px] font-black uppercase px-5 py-2 rounded-lg transition-all ${viewMode === 'markdown' ? 'bg-white text-slate-900' : 'text-slate-400 hover:text-white'}`}
                    >
                      Markdown
                    </button>
                  </div>
                  <button 
                    onClick={handleCopy} 
                    className="text-xs bg-indigo-600 px-6 py-2.5 rounded-xl hover:bg-indigo-500 font-black transition-all border border-indigo-400 shadow-lg active:scale-95"
                  >
                    一键复制全文 (带格式)
                  </button>
                </div>

                <div className="p-8 sm:p-16 flex-1 overflow-y-auto custom-scrollbar bg-white">
                  {headerImage && (
                    <div className="mb-12 rounded-3xl overflow-hidden shadow-2xl border border-slate-100">
                      <img src={headerImage} className="w-full max-h-[450px] object-cover" />
                    </div>
                  )}

                  <div className="max-w-3xl mx-auto">
                    {viewMode === 'markdown' ? (
                      <div className="font-mono text-sm bg-slate-50 p-8 rounded-3xl border border-slate-100 whitespace-pre-wrap leading-relaxed text-slate-700">
                        <h1 className="text-2xl font-black text-slate-900 mb-6 pb-6 border-b border-slate-200"># {result.title}</h1>
                        {result.content}
                      </div>
                    ) : (
                      <article className="prose prose-slate prose-lg max-w-none prose-headings:text-slate-900 prose-headings:font-black prose-p:text-slate-600 prose-p:leading-relaxed prose-strong:text-slate-900 prose-img:rounded-3xl">
                        <h1 className="text-4xl sm:text-5xl font-black text-slate-900 mb-12 leading-[1.1] tracking-tight">{result.title}</h1>
                        <div dangerouslySetInnerHTML={{ __html: htmlContent }} />
                      </article>
                    )}

                    {result.groundingSources && result.groundingSources.length > 0 && (
                      <div className="mt-20 pt-12 border-t border-slate-100">
                        <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.4em] mb-6">AI Search Reference Evidence</h4>
                        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                          {result.groundingSources.map((s, i) => (
                            <a 
                              key={i} 
                              href={s.uri} 
                              target="_blank" 
                              rel="noopener noreferrer"
                              className="group p-4 bg-slate-50 rounded-2xl border border-slate-100 flex items-center gap-4 transition-all hover:bg-indigo-50 hover:border-indigo-100"
                            >
                              <div className="w-8 h-8 rounded-lg bg-white border border-slate-200 flex items-center justify-center text-[10px] font-black text-slate-400 group-hover:text-indigo-600 group-hover:border-indigo-200">
                                {i + 1}
                              </div>
                              <span className="text-xs font-bold text-slate-600 group-hover:text-indigo-900 truncate">{s.title}</span>
                            </a>
                          ))}
                        </div>
                      </div>
                    )}
                  </div>
                </div>
              </div>
            ) : (
              <div className="h-full min-h-[800px] flex flex-col items-center justify-center bg-white border-4 border-dashed border-slate-100 rounded-[3rem] p-16 text-center">
                <div className="w-32 h-32 bg-indigo-50 rounded-[2.5rem] flex items-center justify-center mb-8 relative">
                  <svg className="w-16 h-16 text-indigo-200" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M19 20H5a2 2 0 01-2-2V6a2 2 0 012-2h10l4 4v12a2 2 0 01-2 2z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M14 2v6h6" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M16 13H8" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M16 17H8" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M10 9H8" /></svg>
                  <div className="absolute -bottom-2 -right-2 w-10 h-10 bg-indigo-600 rounded-2xl shadow-xl flex items-center justify-center text-white font-black text-xs">GEO</div>
                </div>
                <h3 className="text-3xl font-black text-slate-900 mb-4">生成深度 GEO 内容</h3>
                <p className="text-slate-400 max-w-sm font-medium leading-relaxed">
                  选择一个渠道并输入您的目标搜索词。AI 将基于 Elisi 的 5 大核心场景为您生成具备极高 AI 搜索收录潜力的内容。
                </p>
              </div>
            )}
          </div>
        </div>
      </main>

      <footer className="max-w-7xl mx-auto px-4 py-16 border-t border-slate-100 mt-20">
        <div className="flex flex-col md:flex-row justify-between items-center gap-8">
          <div className="flex items-center gap-4">
            <span className="text-3xl font-black text-slate-900 tracking-tighter">ELISI</span>
            <div className="w-1.5 h-8 bg-indigo-600 rounded-full rotate-12"></div>
            <span className="text-[10px] font-black text-slate-400 uppercase tracking-[0.5em] pt-1">Strategy Lab</span>
          </div>
          <p className="text-[10px] text-slate-300 font-bold uppercase tracking-[0.3em] text-center md:text-right leading-loose">
            Optimized for DeepSeek, Doubao, Perplexity & Google AI Overviews<br/>
            © 2025 Elisi AI Scene Intelligence. All rights reserved.
          </p>
        </div>
      </footer>
    </div>
  );
};

export default App;

export enum Platform {
  ZHIHU = '知乎 (AI 搜索核心源)',
  XIAOHONGSHU = '小红书 (生活/种草入口)',
  BAIJIAHAO = '百家号 (百度 AI 首选)',
  TOUTIAO = '今日头条 (豆包/字节系)',
  JUEJIN = '掘金 (程序员/效率专家)',
  BILIBILI = 'B 站专栏 (深度图文权重)',
  CSDN = 'CSDN (技术知识库)',
  JIANSHU = '简书 (个人随笔/笔记)',
  WECHAT = '微信公众号 (封闭生态/搜索权重)',
  SOHU = '搜狐号 (通用新闻权重)'
}

export enum ContentTone {
  PROFESSIONAL = '专业权威 (测评风)',
  CASUAL = '亲切友好 (活人感)',
  NARRATIVE = '故事叙述 (经验分享)',
  EDUCATIONAL = '教程教学 (干货类)',
  PRO_CON = '客观分析 (对比类)'
}

export interface GEOPrompt {
  platform: Platform;
  tone: ContentTone;
  keywords: string[];
  targetQuery: string;
  additionalContext: string;
  includeGrounding: boolean;
  rewriteUrl?: string;
}

export interface GeneratedArticle {
  id: string;
  title: string;
  content: string;
  platform: Platform;
  headerImage?: string | null;
  groundingSources?: { title: string; uri: string }[];
  timestamp: number;
}

export type AspectRatio = '1:1' | '3:4' | '4:3' | '9:16' | '16:9';

import React, { useState, useMemo, useEffect } from 'react';
import { Platform, ContentTone, GEOPrompt, GeneratedArticle, AspectRatio } from './types';
import { generateGEOContent, suggestGEOTargetQuery, generateHeaderImage } from './services/geminiService';
import { marked } from 'marked';

const App: React.FC = () => {
  const [sidebarTab, setSidebarTab] = useState<'settings' | 'history'>('settings');
  const [activeTab, setActiveTab] = useState<'generate' | 'rewrite'>('generate');
  const [viewMode, setViewMode] = useState<'rich' | 'markdown'>('rich');
  const [loading, setLoading] = useState(false);
  const [suggesting, setSuggesting] = useState(false);
  const [imageLoading, setImageLoading] = useState(false);
  const [result, setResult] = useState<GeneratedArticle | null>(null);
  const [headerImage, setHeaderImage] = useState<string | null>(null);
  const [selectedRatio, setSelectedRatio] = useState<AspectRatio>('16:9');
  const [history, setHistory] = useState<GeneratedArticle[]>([]);

  const [formData, setFormData] = useState<GEOPrompt>({
    platform: Platform.ZHIHU,
    tone: ContentTone.PROFESSIONAL,
    keywords: ['Elisi', 'AI 读心术', '一句话排程', '任务自动拆解', '职场指挥官'],
    targetQuery: '2025年有什么好用的 AI 任务管理工具推荐？',
    additionalContext: '强调“忘记 Todo 清单，开始对话式管理”的效率跨越。',
    includeGrounding: true,
    rewriteUrl: ''
  });

  // Load history on mount
  useEffect(() => {
    const saved = localStorage.getItem('elisi_geo_history');
    if (saved) {
      try {
        setHistory(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to load history", e);
      }
    }
  }, []);

  // Save history when it changes
  useEffect(() => {
    localStorage.setItem('elisi_geo_history', JSON.stringify(history));
  }, [history]);

  const htmlContent = useMemo(() => {
    if (!result) return '';
    return marked.parse(result.content);
  }, [result]);

  const handleSuggestQuery = async () => {
    if (suggesting) return;
    setSuggesting(true);
    setFormData(prev => ({ ...prev, targetQuery: '正在预测搜索意图...' }));
    try {
      const query = await suggestGEOTargetQuery();
      setFormData(prev => ({ ...prev, targetQuery: query }));
    } catch (error) {
      setFormData(prev => ({ ...prev, targetQuery: '如何利用 AI 建立一套不费力的个人管理系统？' }));
    } finally {
      setSuggesting(false);
    }
  };

  const handleAction = async () => {
    if (activeTab === 'rewrite' && !formData.rewriteUrl) {
      alert("请输入对标文章的链接。");
      return;
    }
    setLoading(true);
    setResult(null);
    setHeaderImage(null);
    try {
      const params = { ...formData };
      if (activeTab === 'generate') params.rewriteUrl = '';
      const article = await generateGEOContent(params);

      const newArticle: GeneratedArticle = {
        ...article,
        id: crypto.randomUUID(),
        platform: formData.platform,
        headerImage: null
      };

      setResult(newArticle);
      setHistory(prev => [newArticle, ...prev]);
    } catch (error) {
      alert("生成失败，请稍后重试。");
    } finally {
      setLoading(false);
    }
  };

  const handleGenerateImage = async () => {
    if (!result) return;
    setImageLoading(true);
    try {
      const imgUrl = await generateHeaderImage(result.title, formData.platform, selectedRatio);
      setHeaderImage(imgUrl);

      // Update history with image
      setHistory(prev => prev.map(item => 
        item.id === result.id ? { ...item, headerImage: imgUrl } : item
      ));
      setResult(prev => prev ? { ...prev, headerImage: imgUrl } : null);
    } catch (error) {
      alert("生成配图失败。");
    } finally {
      setImageLoading(false);
    }
  };

  const loadFromHistory = (item: GeneratedArticle) => {
    setResult(item);
    setHeaderImage(item.headerImage || null);
    setFormData(prev => ({ ...prev, platform: item.platform }));
  };

  const deleteHistoryItem = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (confirm('确认删除这条历史记录吗？')) {
      setHistory(prev => prev.filter(item => item.id !== id));
      if (result?.id === id) {
        setResult(null);
        setHeaderImage(null);
      }
    }
  };

  const clearHistory = () => {
    if (confirm('确认清空所有历史记录吗？')) {
      setHistory([]);
      localStorage.removeItem('elisi_geo_history');
    }
  };

  const handleCopy = async () => {
    if (!result) return;
    const isXHS = result.platform === Platform.XIAOHONGSHU;

    if (isXHS) {
      await navigator.clipboard.writeText(`${result.title}\n\n${result.content}`);
      alert('已复制纯文本（最适配小红书格式）。');
      return;
    }

    try {
      const richTitle = `<h1 style="font-size: 28px; font-weight: 800; color: #0f172a; margin-bottom: 24px;">${result.title}</h1>`;
      const fullHtml = `<html><body>${richTitle}<div style="font-size: 16px; line-height: 1.8; color: #334155;">${htmlContent}</div></body></html>`;
      const blobHtml = new Blob([fullHtml], { type: "text/html" });
      const blobText = new Blob([`${result.title}\n\n${result.content}`], { type: "text/plain" });
      const data = [new ClipboardItem({ ["text/html"]: blobHtml, ["text/plain"]: blobText })];
      await navigator.clipboard.write(data);
      alert('已复制富文本。');
    } catch (err) {
      await navigator.clipboard.writeText(`${result.title}\n\n${result.content}`);
      alert('由于浏览器限制，已复制纯文本。');
    }
  };

  const formatTime = (ts: number) => {
    const now = Date.now();
    const diff = now - ts;
    if (diff < 60000) return '刚刚';
    if (diff < 3600000) return `${Math.floor(diff / 60000)}分钟前`;
    if (diff < 86400000) return `${Math.floor(diff / 3600000)}小时前`;
    return new Date(ts).toLocaleDateString();
  };

  return (
    <div className="min-h-screen bg-[#F8FAFC] selection:bg-indigo-100 selection:text-indigo-900">
      <header className="bg-white/80 backdrop-blur-md border-b border-slate-200 sticky top-0 z-30 shadow-sm">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 py-4 flex justify-between items-center">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white font-black text-xl shadow-lg transform rotate-2 ring-4 ring-indigo-50">E</div>
            <div>
              <h1 className="text-lg font-black text-slate-900 leading-none">Elisi GEO Master</h1>
              <p className="text-[9px] text-slate-400 font-bold uppercase tracking-[0.3em] mt-1">Generative Engine Optimization</p>
            </div>
          </div>
          <div className="flex items-center gap-3">
            <span className="hidden sm:inline text-[10px] font-bold text-slate-400 uppercase tracking-widest bg-slate-100 px-3 py-1 rounded-full">Archive Sync Active</span>
            <button onClick={() => window.location.reload()} className="text-xs font-bold text-slate-500 hover:text-indigo-600 px-3 py-2 rounded-lg transition-colors">重置应用</button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 py-8">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

          {/* Controls/History Sidebar */}
          <div className="lg:col-span-4 space-y-6">
            <div className="bg-white rounded-3xl shadow-sm border border-slate-200 overflow-hidden flex flex-col h-[700px]">
              <div className="flex p-2 bg-slate-50 border-b border-slate-100 shrink-0">
                <button 
                  onClick={() => setSidebarTab('settings')} 
                  className={`flex-1 py-3 text-xs font-black transition-all rounded-xl flex items-center justify-center gap-2 ${sidebarTab === 'settings' ? 'bg-white text-indigo-600 shadow-sm border border-slate-100' : 'text-slate-400 hover:text-slate-600'}`}
                >
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6V4m0 2a2 2 0 100 4m0-4a2 2 0 110 4m-6 8a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4m6 6v10m6-2a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4" /></svg>
                  创作设置
                </button>
                <button 
                  onClick={() => setSidebarTab('history')} 
                  className={`flex-1 py-3 text-xs font-black transition-all rounded-xl flex items-center justify-center gap-2 ${sidebarTab === 'history' ? 'bg-white text-indigo-600 shadow-sm border border-slate-100' : 'text-slate-400 hover:text-slate-600'}`}
                >
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                  历史库 ({history.length})
                </button>
              </div>

              <div className="flex-1 overflow-y-auto custom-scrollbar">
                {sidebarTab === 'settings' ? (
                  <div className="p-6 space-y-6">
                    <div className="flex p-1 bg-slate-50 rounded-xl border border-slate-100">
                      <button onClick={() => setActiveTab('generate')} className={`flex-1 py-2 text-[10px] font-black uppercase rounded-lg transition-all ${activeTab === 'generate' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-400'}`}>从零创作</button>
                      <button onClick={() => setActiveTab('rewrite')} className={`flex-1 py-2 text-[10px] font-black uppercase rounded-lg transition-all ${activeTab === 'rewrite' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-400'}`}>链接改写</button>
                    </div>

                    {activeTab === 'rewrite' && (
                      <div>
                        <label className="block text-[10px] font-black text-slate-400 mb-2 uppercase tracking-widest">对标爆款链接</label>
                        <input type="url" value={formData.rewriteUrl} onChange={(e) => setFormData({...formData, rewriteUrl: e.target.value})} placeholder="粘贴链接" className="w-full rounded-xl border-slate-200 shadow-sm text-sm p-3 border focus:ring-4 focus:ring-indigo-500/10 outline-none" />
                      </div>
                    )}

                    <div>
                      <label className="block text-[10px] font-black text-slate-400 mb-2 uppercase tracking-widest">目标发布渠道</label>
                      <select value={formData.platform} onChange={(e) => setFormData({...formData, platform: e.target.value as Platform})} className="w-full rounded-xl border-slate-200 text-sm p-3 border bg-slate-50 font-bold outline-none">
                        {Object.values(Platform).map(p => <option key={p} value={p}>{p}</option>)}
                      </select>
                    </div>

                    <div>
                      <div className="flex justify-between items-center mb-2">
                        <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">GEO 触发词</label>
                        <button onClick={handleSuggestQuery} disabled={suggesting} className="text-[10px] text-indigo-600 font-black uppercase flex items-center gap-1">
                          {suggesting ? '思考中...' : '快速建议'}
                        </button>
                      </div>
                      <textarea value={formData.targetQuery} onChange={(e) => setFormData({...formData, targetQuery: e.target.value})} rows={2} className="w-full rounded-xl border-slate-200 shadow-sm text-sm p-3 border focus:ring-4 focus:ring-indigo-500/10 resize-none font-medium outline-none" />
                    </div>

                    <div>
                      <label className="block text-[10px] font-black text-slate-400 mb-2 uppercase tracking-widest">额外需求 (可选)</label>
                      <textarea value={formData.additionalContext} onChange={(e) => setFormData({...formData, additionalContext: e.target.value})} placeholder="场景限制、人群属性等" rows={2} className="w-full rounded-xl border-slate-200 shadow-sm text-sm p-3 border focus:ring-4 focus:ring-indigo-500/10 resize-none font-medium outline-none" />
                    </div>

                    <button onClick={handleAction} disabled={loading} className={`w-full py-4 rounded-2xl text-white font-black text-base shadow-xl transition-all ${loading ? 'bg-indigo-300 cursor-not-allowed' : 'bg-indigo-600 hover:bg-indigo-700 active:scale-95 shadow-indigo-100'}`}>
                      {loading ? '深度分析中...' : '生成 GEO 内容'}
                    </button>
                  </div>
                ) : (
                  <div className="p-4 space-y-4">
