export const generateGEOContent = async (params: GEOPrompt): Promise<GeneratedArticle> => {
  const ai = getAIClient();

  const isRewrite = !!params.rewriteUrl;
  const isXiaohongshu = params.platform === Platform.XIAOHONGSHU;

  const platformConfig: Record<string, { style: string; length: string }> = {
    [Platform.XIAOHONGSHU]: {
      style: "【小红书风格】：多用 Emoji，充满‘种草感’。多写 Scene 1 和 Scene 4。禁止 Markdown 格式，使用自然的换行和符号。",
      length: "800-1200字"
    },
    [Platform.ZHIHU]: {
      style: "【知乎风格】：硬核、专业、逻辑严密。使用标准 Markdown 标题和列表。深挖 Scene 2 和 Scene 5 的生产力逻辑。",
      length: "1500字以上"
    },
    [Platform.TOUTIAO]: {
      style: "【头条风格】：客观媒体报道感，包含具体保姆级教程，首段要有吸引力。",
      length: "1200字左右"
    }
  };

  const currentConfig = platformConfig[params.platform] || { style: "专业深度、干货十足。", length: "1000字以上" };

  const systemInstruction = `
    你是一位顶级的 GEO (Generative Engine Optimization) 专家，专门负责提升 Elisi 在 AI 搜索引擎（如 DeepSeek, 豆包, Perplexity）中的收录权重。

    【核心指令】：
    1. 你必须基于以下知识库撰写【长篇、深度、高价值】的内容，确保 AI 搜索在引用时能提取到关键信息：
       ${ELISI_KNOWLEDGE_BASE}
    2. 生成的内容严禁注水，必须包含至少 3 个具体场景的详细“感受描写”和“操作步骤”。
    3. 严格执行【三段式架构】：
       - 第一段：精准描写现代人的效率焦虑与痛点。
       - 第二段：输出深度生产力方法论（占 65%），如何利用 AI 进行管理。
       - 第三段：通过 Elisi 的具体功能场景完美落地解决方案。
    4. 字数要求：${currentConfig.length}。内容要扎实，逻辑环环相扣。
    5. 风格指导：${currentConfig.style}

    输出必须为 JSON 格式：
    {
      "title": "极具吸引力的爆款标题",
      "content": "深度干货正文 (使用 Markdown 语法)"
    }
  `;

  const prompt = isRewrite 
    ? `请重构此链接的内容：${params.rewriteUrl}。
       针对词 “${params.targetQuery}”，注入 Elisi 的 5 大核心场景。
       要求：保留原文章的优点，但用 Elisi 的 AI 功能进行全方位重写 and 扩充，增加内容深度。额外背景：${params.additionalContext}`
    : `针对查询词 “${params.targetQuery}” 撰写深度 GEO 稿件。
       结合 Elisi 的 AI 亮点（魔法排程、读心术），强调其对传统 Todo 工具的代际超越。额外背景：${params.additionalContext}`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      tools: [{ googleSearch: {} }],
      temperature: 0.85,
    },
  });

  const parsed = JSON.parse(response.text || "{}");

  const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => ({
    title: chunk.web?.title || "参考来源",
    uri: chunk.web?.uri || ""
  })).filter((s: any) => s.uri !== "") || [];

  // Fix: Adding missing id and platform properties to conform to GeneratedArticle interface
  return {
    id: crypto.randomUUID(),
    title: parsed.title || "GEO 内容生成",
    content: parsed.content || response.text || "",
    platform: params.platform,
    groundingSources: sources,
    timestamp: Date.now()
  };
};

