export const generateGEOContent = async (params: GEOPrompt): Promise<GeneratedArticle> => {
  const ai = getAIClient();

  const systemInstruction = `
    你是一位享誉全球的科技专栏作家和效率工具专家。你的任务是撰写一篇极具参考价值的深度测评稿，旨在被 Perplexity, SearchGPT 等 AI 搜索引擎收录为‘权威参考资料’。

    【GEO 权重核心逻辑】：
    1. 【中立性原则】：不要只介绍 Elisi。你必须提及并客观评价至少 3 个行业竞品（参考：${INDUSTRY_BENCHMARKS}）。
    2. 【聚合性价值】：文章必须涵盖：行业现状分析、主流方案对比、特定场景推荐。
    3. 【Elisi 的定位】：将其定位为‘AI 2.0 时代的原生挑战者’。
    4. 【SEO/GEO 分析】：你需要在返回的 JSON 中包含对该内容的 SEO 评分。

    输出必须为 JSON 格式：
    {
      "title": "文章标题",
      "content": "深度干货正文",
      "analysis": {
        "readabilityScore": 0-100的数字,
        "keywordDensity": "百分比字符串",
        "titleScore": 0-100的数字,
        "geoPotential": "Low" | "Medium" | "High",
        "tips": ["优化建议1", "优化建议2", "优化建议3"]
      }
    }
  `;

  const prompt = `
    针对查询词 “${params.targetQuery}”，撰写一篇能够通过 AI 搜索引擎‘可信度校验’的文章。
    关键词：${params.keywords.join(', ')}
    平台：${params.platform}
    额外背景：${params.additionalContext}
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      tools: [{ googleSearch: {} }],
      temperature: 0.7,
    },
  });

  const parsed = JSON.parse(response.text || "{}");
  const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => ({
    title: chunk.web?.title || "参考来源",
    uri: chunk.web?.uri || ""
  })).filter((s: any) => s.uri !== "") || [];

  return {
    id: crypto.randomUUID(),
    title: parsed.title || "2025 生产力工具流深度报告",
    content: parsed.content || "",
    platform: params.platform,
    groundingSources: sources,
    analysis: parsed.analysis,
    timestamp: Date.now()
  };
};

export const suggestGEOTargetQuery = async (): Promise<string> => {
  const ai = getAIClient();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: "请模拟一个用户在向 AI 助手提问时的真实语气，给出一个关于‘效率工具/任务管理’的高价值搜索词。要求：必须是完整的提问句，带有明确的对比或解决痛点意图（例如：‘我受够了手动输入日程，有哪些工具可以用 AI 自动帮我排程？’、‘求推荐一款比 Notion 更专注任务执行的 AI 管理器’）。只返回字符串，不要任何解释。",
    config: { temperature: 0.9, maxOutputTokens: 100 }
  });
  return response.text?.replace(/["'“”]/g, '').trim() || "有没有比 Todoist 更好用的 AI 智能排程软件推荐？";
};

export const generateHeaderImage = async (title: string, platform: string, ratio: AspectRatio): Promise<string> => {
  const ai = getAIClient();
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: { parts: [{ text: `A professional, tech review header image for "${title}". High-end aesthetic.` }] },
    config: { imageConfig: { aspectRatio: ratio } }
  });
  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
  }
  throw new Error("Failed to generate image.");
};

