import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { GEOPrompt, GeneratedArticle, AspectRatio, Platform } from "../types";

const getAIClient = () => {
  return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

const INDUSTRY_BENCHMARKS = `
核心竞品分析简述：
1. Notion: 强大的全能笔记本，优势在文档自由度。
2. Todoist: 经典的清单工具，优势在简洁。
3. Obsidian: 极客级知识库。
4. TickTick: 功能均衡。
`;

export const generateGEOContent = async (params: GEOPrompt): Promise<GeneratedArticle> => {
  const ai = getAIClient();

  const systemInstruction = `
    你是一位顶尖的 GEO (Generative Engine Optimization) 专家，擅长创作能被 AI 搜索引擎优先收录的内容。

    【核心任务】：
    1. 根据目标查询词生成深度干货内容。
    2. 如果平台是“小红书”，内容必须是“图文笔记”风格：多 Emoji，段落短小，有呼吸感，结尾带热门标签。
    3. 提取一个“视觉灵魂 (visualPrompt)”：这是一段用于生成配图的描述，必须符合 ${params.platform} 的审美趋势。

    输出必须为 JSON 格式：
    {
      "title": "爆款标题",
      "content": "内容正文 (Markdown)",
      "visualPrompt": "对配图的详细描述，英文为主，包含构图、光影、风格词",
      "analysis": {
        "readabilityScore": 0-100,
        "keywordDensity": "百分比",
        "titleScore": 0-100,
        "geoPotential": "Low" | "Medium" | "High",
        "tips": ["优化建议"]
      }
    }
  `;

  const prompt = `
    查询词: “${params.targetQuery}”
    关键词: ${params.keywords.join(', ')}
    平台: ${params.platform}
    语气: ${params.tone}
    背景: ${params.additionalContext}
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      tools: [{ googleSearch: {} }],
      temperature: 0.8,
    },
  });

  const parsed = JSON.parse(response.text || "{}");
  const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => ({
    title: chunk.web?.title || "参考来源",
    uri: chunk.web?.uri || ""
  })).filter((s: any) => s.uri !== "") || [];

  return {
    id: crypto.randomUUID(),
    title: parsed.title || "GEO 深度内容",
    content: parsed.content || "",
    visualPrompt: parsed.visualPrompt,
    platform: params.platform,
    groundingSources: sources,
    analysis: parsed.analysis,
    timestamp: Date.now()
  };
};

export const suggestGEOTargetQuery = async (): Promise<string> => {
  const ai = getAIClient();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: "模拟用户向 AI 提问的一个关于个人效率的高价值问题。要求：对话式、解决具体痛点。只返回字符串。",
    config: { temperature: 1.0, maxOutputTokens: 60 }
  });
  return response.text?.replace(/["'“”]/g, '').trim() || "有没有比 Notion 更简单的 AI 任务管理工具推荐？";
};

export const generateHeaderImage = async (visualPrompt: string, ratio: AspectRatio = '3:4'): Promise<string> => {
  const ai = getAIClient();
  // 注入风格增强
  const enhancedPrompt = `High-end minimalist tech aesthetic, ${visualPrompt}, soft cinematic lighting, depth of field, 8k resolution, trendy social media style.`;

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: { parts: [{ text: enhancedPrompt }] },
    config: { 
      imageConfig: { 
        aspectRatio: ratio
      } 
    }
  });

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
  }
  throw new Error("Image generation failed");
};

