    const saved = localStorage.getItem('elisi_geo_history_v2');
    if (saved) {
      try {
        setHistory(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to load history", e);
      }
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('elisi_geo_history_v2', JSON.stringify(history));
  }, [history]);

  const htmlContent = useMemo(() => {
    if (!result) return '';
    return marked.parse(result.content);
  }, [result]);

  const handleSuggestQuery = async () => {
    if (suggesting) return;
    setSuggesting(true);
    try {
      const query = await suggestGEOTargetQuery();
      setFormData(prev => ({ ...prev, targetQuery: query }));
    } catch (error) {
      console.error(error);
    } finally {
      setSuggesting(false);
    }
  };

  const [formData, setFormData] = useState<GEOPrompt>({
    platform: Platform.XIAOHONGSHU,
    tone: ContentTone.CASUAL,
