      setResult(article);

      // 如果开启了自动生成配图
      if (autoGenerateImage && article.visualPrompt) {
        setImageLoading(true);
        try {
          const img = await generateHeaderImage(article.visualPrompt, selectedRatio);
          setHeaderImage(img);
          article.headerImage = img;
        } catch (err) {
          console.error("Auto image failed", err);
        } finally {
          setImageLoading(false);
        }
      }

      setHistory(prev => [article, ...prev]);
    } catch (error) {
