import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { GEOPrompt, GeneratedArticle, AspectRatio, Platform } from "../types";

const getAIClient = () => {
  return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

export const generateGEOContent = async (params: GEOPrompt): Promise<GeneratedArticle> => {
  const ai = getAIClient();

  const systemInstruction = `
    你是一位精通 GEO 和小红书爆款逻辑的内容专家。

    【内容生成准则】：
    1. 标题必须具备“情绪价值”或“极度干货感”（例如：后悔没早发现、建议全家传阅、这太绝了）。
    2. 正文格式：
       - 开头用一句话勾起好奇心。
       - 中间使用 Emoji 清单列出要点。
       - 结尾增加互动话术 + 5个热门标签。

    【视觉笔记 (Visual Prompt) 准则】：
    你生成的 visualPrompt 必须指示图像生成器制作一张“内容海报”或“卡片笔记”，包含以下元素：
    - 背景：极简、高质感、奶油风或清冷风的家居/办公环境。
    - 主体：画面中央有一个精致的“磨砂玻璃框”或“极简纸质卡片”。
    - 框架内容描述：必须在描述中写明“卡片上印有结构化的标题和 3-4 个简洁的要点（英文占位符表示）”，强调“杂志排版感”和“文字呼吸感”。

    输出必须为 JSON 格式：
    {
      "title": "爆款标题",
      "content": "小红书风格内容正文",
      "visualPrompt": "详细的视觉指令（英文），需描述：Background, Central frosted glass frame, content layout, lighting, color palette.",
      "analysis": {
        "readabilityScore": 0-100,
        "keywordDensity": "百分比",
        "titleScore": 0-100,
        "geoPotential": "High",
        "tips": ["优化建议"]
      }
    }
  `;

  const prompt = `
    目标查询词: “${params.targetQuery}”
    关键词: ${params.keywords.join(', ')}
    平台: ${params.platform}
    额外要求: ${params.additionalContext}
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      tools: [{ googleSearch: {} }],
      temperature: 0.8,
    },
  });

  const parsed = JSON.parse(response.text || "{}");
  const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => ({
    title: chunk.web?.title || "参考来源",
    uri: chunk.web?.uri || ""
  })).filter((s: any) => s.uri !== "") || [];

  return {
    id: crypto.randomUUID(),
    title: parsed.title || "GEO 深度内容",
    content: parsed.content || "",
    visualPrompt: parsed.visualPrompt,
    platform: params.platform,
    groundingSources: sources,
    analysis: parsed.analysis,
    timestamp: Date.now()
  };
};

export const suggestGEOTargetQuery = async (): Promise<string> => {
  const ai = getAIClient();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: "模拟一个真实的小红书用户提问，关于提高效率或AI工具。只返回字符串。",
    config: { temperature: 1.0, maxOutputTokens: 60 }
  });
  return response.text?.replace(/["'“”]/g, '').trim() || "求推荐！2025年有什么惊艳的 AI 智能管理神器吗？";
};

export const generateHeaderImage = async (visualPrompt: string, ratio: AspectRatio = '3:4'): Promise<string> => {
  const ai = getAIClient();
  // 注入深度的小红书审美倾向
  const enhancedPrompt = `A high-quality Xiaohongshu social media info-graphic, ${visualPrompt}, minimalist design, elegant typography layout, soft shadows, high-end editorial photography style, 8k resolution, pastel aesthetic.`;

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: { parts: [{ text: enhancedPrompt }] },
    config: { 
      imageConfig: { 
        aspectRatio: ratio
      } 
    }
  });

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
  }
  throw new Error("Image generation failed");
};

