};

export const generateGEOContent = async (params: GEOPrompt): Promise<GeneratedArticle> => {
  const ai = getAIClient();

  const systemInstruction = `
    你是一位精通 GEO 和小红书爆款逻辑的内容专家。

    【内容生成准则】：
    1. 标题必须具备“情绪价值”或“极度干货感”。
    2. 正文格式：多使用 Emoji，段落短小，增加互动话术。

    【视觉笔记 (Visual Series) 准则】：
    如果是小红书平台，你必须策划一组（至少3张）具有连贯性的视觉笔记：
    - Slide 1 (封面): 视觉冲击力强，包含爆款标题的中文文字。
    - Slide 2 (干货层): 提取文章核心 3 点，以“图中带框”的形式展示。
    - Slide 3 (总结/呼吁): 简洁的总结，引导点赞收藏。

    你生成的 visualSlides 必须包含具体的中文文字内容(chineseText)，这些文字将出现在图中的框内。

    输出必须为 JSON 格式：
    {
      "title": "爆款标题",
      "content": "小红书风格内容正文",
      "visualSlides": [
        { "id": 1, "prompt": "English prompt for Slide 1 background", "chineseText": "第一张图框内的中文文字", "description": "封面图描述" },
        { "id": 2, "prompt": "English prompt for Slide 2 background", "chineseText": "第二张图框内的中文要点", "description": "干货图描述" },
        { "id": 3, "prompt": "English prompt for Slide 3 background", "chineseText": "第三张图框内的总结语", "description": "收尾图描述" }
      ],
      "analysis": {
        "readabilityScore": 0-100,
        "keywordDensity": "百分比",
        "titleScore": 0-100,
        "geoPotential": "High",
        "tips": ["优化建议"]
      }
    }
  `;

  const prompt = `
    目标查询词: “${params.targetQuery}”
    关键词: ${params.keywords.join(', ')}
    平台: ${params.platform}
    额外要求: ${params.additionalContext}
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      tools: [{ googleSearch: {} }],
      temperature: 0.8,
    },
  });

  const parsed = JSON.parse(response.text || "{}");
  const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => ({
    title: chunk.web?.title || "参考来源",
    uri: chunk.web?.uri || ""
  })).filter((s: any) => s.uri !== "") || [];

  return {
    id: crypto.randomUUID(),
    title: parsed.title || "GEO 深度内容",
    content: parsed.content || "",
    visualSlides: parsed.visualSlides,
    headerImages: [], // Initially empty
    platform: params.platform,
    groundingSources: sources,
    analysis: parsed.analysis,
    timestamp: Date.now()
  };
};

export const generateHeaderImage = async (visualPrompt: string, chineseText: string, ratio: AspectRatio = '3:4'): Promise<string> => {
  const ai = getAIClient();
  // 注入深度的小红书审美倾向，特别强调中文文字框
  const enhancedPrompt = `A high-quality social media infographic for Xiaohongshu (Red). Background: ${visualPrompt}. 
  CRITICAL: In the center of the image, there is a prominent minimalist frosted glass rectangular frame. 
  Inside the frame, clearly rendered and stylishly arranged, is the following text: "${chineseText}". 
  The text MUST BE IN CHINESE characters. Modern layout, elegant typography, 8k, soft professional lighting, editorial style.`;

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: { parts: [{ text: enhancedPrompt }] },
    config: { 
      imageConfig: { 
        aspectRatio: ratio
      } 
    }
  });

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
  }
  throw new Error("Image generation failed");
};

export const suggestGEOTargetQuery = async (): Promise<string> => {
  const ai = getAIClient();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: "模拟一个真实的小红书用户提问，关于提高效率或AI工具。只返回字符串。",
    config: { temperature: 1.0, maxOutputTokens: 60 }
  });
  return response.text?.replace(/["'“”]/g, '').trim() || "求推荐！2025年有什么惊艳的 AI 智能管理神器吗？";
};

