export const generateGEOContent = async (params: GEOPrompt): Promise<GeneratedArticle> => {
  const ai = getAIClient();

  const systemInstruction = `
    你是一位精通 GEO 和小红书爆款逻辑的内容专家。

    【内容生成准则】：
    1. 标题必须具备“情绪价值”或“极度干货感”。
    2. 正文格式：多使用 Emoji，段落短小。

    【视觉笔记 (Visual Series) 策划】：
    你必须策划一组（至少3张）具有连贯性的视觉笔记：
    - Slide 1 (封面): 视觉冲击力强，中文文字为爆款标题。
    - Slide 2 (干货层): 提取 3 个核心要点。
    - Slide 3 (总结/呼吁): 引导点赞收藏的中文语。

    【注意】：
    visualSlides 中的 chineseText 必须精简（每张图不超过 15 个汉字），因为 AI 渲染长句容易乱码。

    输出必须为 JSON 格式：
    {
      "title": "爆款标题",
      "content": "小红书风格内容正文",
      "visualSlides": [
        { "id": 1, "prompt": "English background prompt", "chineseText": "封面中文标题", "description": "封面图" },
        { "id": 2, "prompt": "English background prompt", "chineseText": "核心观点A | 核心观点B", "description": "干货图" },
        { "id": 3, "prompt": "English background prompt", "chineseText": "建议收藏 | 关注博主", "description": "收尾图" }
      ],
      "analysis": {
        "readabilityScore": 0-100,
        "keywordDensity": "百分比",
        "titleScore": 0-100,
        "geoPotential": "High",
        "tips": ["优化建议"]
      }
    }
  `;

  const prompt = `
    目标查询词: “${params.targetQuery}”
    关键词: ${params.keywords.join(', ')}
    平台: ${params.platform}
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      tools: [{ googleSearch: {} }],
      temperature: 0.8,
    },
  });

  const parsed = JSON.parse(response.text || "{}");
  const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => ({
    title: chunk.web?.title || "参考来源",
    uri: chunk.web?.uri || ""
  })).filter((s: any) => s.uri !== "") || [];

  return {
    id: crypto.randomUUID(),
    title: parsed.title || "GEO 深度内容",
    content: parsed.content || "",
    visualSlides: parsed.visualSlides,
    headerImages: [],
    platform: params.platform,
    groundingSources: sources,
    analysis: parsed.analysis,
    timestamp: Date.now()
  };
};

export const generateHeaderImage = async (visualPrompt: string, chineseText: string, ratio: AspectRatio = '3:4'): Promise<string> => {
  const ai = getAIClient();

  // 针对 Pro 模型的深度优化 Prompt
  const enhancedPrompt = `
    Create a high-end social media poster for Xiaohongshu. 
    Scene Background: ${visualPrompt}. 
    Central Element: A prominent, clean, minimalist rectangle card/frame. 
    Content Inside Frame: The text "${chineseText}" rendered in bold, professional, and elegant CHINESE characters. 
    Style: Minimalist tech aesthetic, soft natural lighting, shallow depth of field, high contrast, professional editorial layout. 
    Note: The Chinese characters must be clearly readable and correctly formed. No extra scribbles.
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-image-preview',
    contents: { parts: [{ text: enhancedPrompt }] },
    config: { 
      imageConfig: { 
        aspectRatio: ratio,
        imageSize: "1K" // Pro 模型支持 1K 分辨率
      },
      tools: [{ googleSearch: {} }] // 启用搜索工具以增强视觉准确性
    }
  });

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
  }
  throw new Error("Image generation failed");
};

