import { GEOPrompt, GeneratedArticle, AspectRatio, Platform, VisualSlide } from "../types";

const getAIClient = () => {
  return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

export const generateGEOContent = async (params: GEOPrompt): Promise<GeneratedArticle> => {
  const ai = getAIClient();

  const systemInstruction = `
    你是一位精通 GEO (Generative Engine Optimization) 和小红书视觉营销的专家。

    【内容生成准则】：
    1. 标题：必须是爆款风格，包含利益点或情绪点。
    2. 正文：小红书式排版，多 Emoji，段落短。

    【视觉策划 (Visual Strategy) 准则】：
    你必须策划一组（至少3张）具有高度连贯性的视觉笔记方案：
    - Slide 1 (封面): 视觉冲击力强，中文文字为爆款标题。提供详细的绘图 Prompt。
    - Slide 2 (干货层): 提取内容核心 3 点，以“图中带框”的形式展示。
    - Slide 3 (总结/呼吁): 简洁的总结，引导点赞收藏。

    【Prompt 要求】：
    - 绘图 Prompt 必须使用英文，包含：构图 (Composition)、光影 (Lighting)、风格关键词 (Minimalist, Editorial, 8k)。
    - chineseText 必须是完整、有力的短句，用于作为图片上的核心文案。

    输出必须为 JSON 格式：
    {
      "title": "爆款标题",
      "content": "内容正文",
      "visualSlides": [
        { "id": 1, "prompt": "Detailed English Drawing Prompt", "chineseText": "图上要写的中文标题", "description": "封面图设计思路" },
        { "id": 2, "prompt": "Detailed English Drawing Prompt", "chineseText": "干货要点中文", "description": "核心内容页说明" },
        { "id": 3, "prompt": "Detailed English Drawing Prompt", "chineseText": "引导语中文", "description": "转化页说明" }
      ],
      "analysis": {
        "readabilityScore": 0-100,
        "keywordDensity": "百分比",
        "titleScore": 0-100,
        "geoPotential": "High",
        "tips": ["优化建议"]
      }
    }
  `;

  const prompt = `
    目标查询词: “${params.targetQuery}”
    关键词: ${params.keywords.join(', ')}
    平台: ${params.platform}
    额外要求: ${params.additionalContext}
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      tools: [{ googleSearch: {} }],
      temperature: 0.8,
    },
  });

  const parsed = JSON.parse(response.text || "{}");
  const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => ({
    title: chunk.web?.title || "参考来源",
    uri: chunk.web?.uri || ""
  })).filter((s: any) => s.uri !== "") || [];

  return {
    id: crypto.randomUUID(),
    title: parsed.title || "GEO 深度内容",
    content: parsed.content || "",
    visualSlides: parsed.visualSlides,
    headerImages: [], 
    platform: params.platform,
    groundingSources: sources,
    analysis: parsed.analysis,
    timestamp: Date.now()
  };
};

export const suggestGEOTargetQuery = async (): Promise<string> => {
  const ai = getAIClient();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: "模拟一个真实的小红书用户在寻找效率工具或日程管理软件时的提问或吐槽。要求：语气真实，包含具体痛点，字数在30-60字左右，必须是一个表达完整的句子。严禁只返回几个字。直接返回字符串内容，不要包含引号。",
    config: { temperature: 1.0, maxOutputTokens: 200 }
  });
  return response.text?.replace(/["'“”]/g, '').trim() || "求推荐！2025年有什么惊艳的 AI 效率神器吗？感觉现在的工具都太复杂了，有没有那种一句话就能排好日程的？";
};

export const generateHeaderImage = async (visualPrompt: string, chineseText: string, ratio: AspectRatio = '3:4'): Promise<string> => {
  const ai = getAIClient();
  const enhancedPrompt = `A high-quality social media infographic. Background: ${visualPrompt}. 
  CRITICAL: Central minimalist frosted glass rectangular frame. 
  Inside the frame, the text: "${chineseText}" in bold, elegant CHINESE characters. Modern layout, 8k.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-image-preview',
    contents: { parts: [{ text: enhancedPrompt }] },
    config: { imageConfig: { aspectRatio: ratio } }
  });

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
  }
  throw new Error("Failed");
};

