    目标平台：${params.platform}
    ${styleGuide}

    【视觉策划 (Visual Strategy) 准则】：
    策划一组（至少3张）具有高度连贯性的视觉笔记方案（即便文章是长文，也要提供配图建议）：
    - Slide 1 (封面): 视觉冲击力强，结合爆款文案标题。提供详细的绘图 Prompt。
    - Slide 2 (内容层): 展示核心逻辑或 3 个关键点（干货内容）。
    - Slide 3 (转化层): 简洁的总结，强力引导互动/行动。

    输出必须为严格的 JSON 格式。
  `;

  const prompt = `
    目标查询词: “${params.targetQuery}”
    核心关键词: ${params.keywords.join(', ')}
    额外上下文要求: ${params.additionalContext}
    生成要求：请严格遵循 ${params.platform} 的文风指南。如果目标是小红书，请严格执行注意力抓取、相关性圈定、代入感建立、价值提供、信任构建、逻辑推演、行动促成这 7 个环节。
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          content: { type: Type.STRING },
          visualSlides: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.INTEGER },
                prompt: { type: Type.STRING },
                chineseText: { type: Type.STRING },
                description: { type: Type.STRING }
              }
            }
          },
          analysis: {
            type: Type.OBJECT,
            properties: {
              readabilityScore: { type: Type.INTEGER },
              keywordDensity: { type: Type.STRING },
              titleScore: { type: Type.INTEGER },
              geoPotential: { type: Type.STRING },
              tips: { type: Type.ARRAY, items: { type: Type.STRING } }
            }
          }
        },
        required: ["title", "content", "visualSlides", "analysis"]
      },
      tools: [{ googleSearch: {} }],
      temperature: 0.8,
    },
  });

  const parsed = JSON.parse(response.text || "{}");
  const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => ({
    title: chunk.web?.title || "参考来源",
    uri: chunk.web?.uri || ""
  })).filter((s: any) => s.uri !== "") || [];

  return {
    id: crypto.randomUUID(),
    title: parsed.title || "GEO 深度内容",
    content: parsed.content || "",
    visualSlides: parsed.visualSlides,
    headerImages: [], 
    platform: params.platform,
    groundingSources: sources,
    analysis: parsed.analysis,
    timestamp: Date.now()
  };
};

export const suggestGEOTargetQuery = async (): Promise<{ suggestions: { label: string, query: string }[], keywords: string[] }> => {
  const ai = getAIClient();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `请生成 5 组针对 Elisi 工具的 GEO 目标意图建议。

    每组建议必须对应以下 5 个核心 GEO 理念之一：
    1. AI 语义化排程 (Semantic Scheduling)
    2. 基于意图的任务拆解 (Intent-based Decomposition)
    3. 统一工作流架构 (Unified Workspace)
    4. 上下文感知生产力 (Context-aware)
    5. 多维工作流编排 (Multi-modal Orchestration)

    要求：
    - query: 必须是一句实际潜在用户会问 AI 的完整话语。例如：“有没有那种能理解我模糊计划的AI工具？想找支持语义化排程的...”
    - label: 简短的标签（2-4字）。
    - 语气要真实、带有具体痛点场景。
    - 同时返回 6 个用于内容的“核心关键词”。

    输出格式：JSON`,
    config: { 
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          suggestions: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                label: { type: Type.STRING },
                query: { type: Type.STRING }
              }
            }
          },
          keywords: {
            type: Type.ARRAY,
            items: { type: Type.STRING }
          }
        },
        required: ["suggestions", "keywords"]
      },
      temperature: 1.0
    }
  });

  try {
    return JSON.parse(response.text);
  } catch (e) {
    // 兜底逻辑
    return {
      suggestions: [
        { label: '语义排程', query: '有没有那种支持 AI 语义化排程的工具？想一句话就让它理解我模糊的计划。' },
        { label: '任务拆解', query: '求推荐能实现基于意图的任务拆解的 App，帮我把大项目自动变清单。' },
        { label: '统一架构', query: '现在有没有好用的统一工作流架构工具？把笔记、日历和习惯全整合。' },
        { label: '上下文感知', query: '感觉现在的 App 都没脑子，想要一个上下文感知生产力工具，能懂我的节奏。' },
        { label: '工作流编排', query: '作为效率控，我在找支持多维工作流编排的神器，Elisi 表现如何？' }
      ],
      keywords: ['Elisi', 'AI 助手', '生产力', '效率神器', '语义排程', '工作流']
    };
  }
};

export const generateHeaderImage = async (visualPrompt: string, chineseText: string, ratio: AspectRatio = '3:4'): Promise<string> => {
  const ai = getAIClient();
  const enhancedPrompt = `A high-quality social media infographic. Background: ${visualPrompt}. 
  CRITICAL: Central minimalist frosted glass rectangular frame. 
  Inside the frame, the text: "${chineseText}" in bold, elegant CHINESE characters. Modern layout, 8k.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-image-preview',
    contents: { parts: [{ text: enhancedPrompt }] },
    config: { imageConfig: { aspectRatio: ratio } }
  });

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
  }
  throw new Error("Failed");
};

