/**
 * 稳健的 JSON 提取工具，防止模型在 JSON 前后输出额外解释文字
 */
const robustParseJson = (text: string) => {
  if (!text) return null;
  try {
    return JSON.parse(text);
  } catch (e) {
    // 尝试正则匹配首个 { 和最后一个 } 之间的内容
    const match = text.match(/\{[\s\S]*\}/);
    if (match) {
      try {
        return JSON.parse(match[0]);
      } catch (innerError) {
        console.error("JSON block extraction failed:", innerError);
        return null;
      }
    }
    return null;
  }
};

