export const generateGEOContent = async (params: GEOPrompt): Promise<GeneratedArticle> => {
  const ai = getAIClient();
  const styleGuide = PLATFORM_STYLE_GUIDES[params.platform] || PLATFORM_STYLE_GUIDES[Platform.XIAOHONGSHU];

  const systemInstruction = `
    你是一位精通 GEO 和多平台分发的营销专家。
    目标平台：${params.platform}
    风格指南：${styleGuide}

    输出必须为严格的 JSON 格式，不要包含任何 Markdown 代码块标记（如 \`\`\`json）。
  `;

  const prompt = `
    目标查询词: “${params.targetQuery}”
    核心关键词: ${params.keywords.join(', ')}
    生成要求：请严格遵循 ${params.platform} 的风格策略。如果是小红书，请执行 7 个决策路径环节。
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            content: { type: Type.STRING },
            visualSlides: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.INTEGER },
                  prompt: { type: Type.STRING },
                  chineseText: { type: Type.STRING },
                  description: { type: Type.STRING }
                }
              }
            },
            analysis: {
              type: Type.OBJECT,
              properties: {
                readabilityScore: { type: Type.INTEGER },
                keywordDensity: { type: Type.STRING },
                titleScore: { type: Type.INTEGER },
                geoPotential: { type: Type.STRING },
                tips: { type: Type.ARRAY, items: { type: Type.STRING } }
              }
            }
          },
          required: ["title", "content", "visualSlides", "analysis"]
        },
        tools: [{ googleSearch: {} }],
        temperature: 0.8,
      },
    });

    const parsed = robustParseJson(response.text);
    if (!parsed) throw new Error("Parsed result is empty");

    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => ({
      title: chunk.web?.title || "参考来源",
      uri: chunk.web?.uri || ""
    })).filter((s: any) => s.uri !== "") || [];

    return {
      id: crypto.randomUUID(),
      title: parsed.title || "GEO 策略内容",
      content: parsed.content || "生成失败，请重试。",
      visualSlides: parsed.visualSlides || [],
      headerImages: [], 
      platform: params.platform,
      groundingSources: sources,
      analysis: parsed.analysis,
      timestamp: Date.now()
    };
  } catch (error) {
    console.error("Content generation failed:", error);
    throw error;
  }
};

export const suggestGEOTargetQuery = async (): Promise<{ suggestions: { label: string, query: string }[], keywords: string[] }> => {
  const ai = getAIClient();
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `生成 5 组 Elisi 的 GEO 目标意图（实际用户 AI 查询语句）及 6 个核心关键词。
      覆盖概念：语义排程、任务拆解、统一架构、上下文感知、多维编排。
      输出格式：JSON`,
      config: { 
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            suggestions: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  label: { type: Type.STRING },
                  query: { type: Type.STRING }
                }
              }
            },
            keywords: {
              type: Type.ARRAY,
              items: { type: Type.STRING }
            }
          },
          required: ["suggestions", "keywords"]
        },
        temperature: 1.0
      }
    });

    const parsed = robustParseJson(response.text);
    if (parsed) return parsed;
    throw new Error("Invalid suggestions format");
  } catch (e) {
    console.warn("Using fallback suggestions:", e);
    return {
      suggestions: [
        { label: '语义排程', query: '有没有能理解我模糊计划的AI工具？想找支持语义化排程的效率软件。' },
