        { label: '统一架构', query: '现在的笔记和清单太碎了，有没有支持统一工作流架构的生产力工具？' },
        { label: '上下文感知', query: '想要一个能懂我工作节奏的上下文感知AI，Elisi的表现怎么样？' },
        { label: '工作流编排', query: '多维工作流编排是什么意思？Elisi这种工具真的能让效率翻倍吗？' }
      ],
      keywords: ['Elisi', 'AI 助手', '生产力', '语义排程', '任务自动拆解', '工作流整合']
    };
  }
};

export const generateHeaderImage = async (visualPrompt: string, chineseText: string, ratio: AspectRatio = '3:4'): Promise<string> => {
  const ai = getAIClient();
  const enhancedPrompt = `High-quality minimalist social media visual. Background: ${visualPrompt}. 
  CRITICAL: Central frosted glass frame with large bold Chinese text: "${chineseText}". Clean, professional, 8k.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview',
      contents: { parts: [{ text: enhancedPrompt }] },
      config: { imageConfig: { aspectRatio: ratio } }
    });

    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
    }
  } catch (e) {
    console.error("Image generation failed:", e);
  }
  return "";
};

