const getAIClient = () => {
  return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

async function retry<T>(fn: () => Promise<T>, retries = 3, delay = 1000): Promise<T> {
  try {
    return await fn();
  } catch (error: any) {
    if (retries <= 1) throw error;
    const isRetryable = error?.message?.includes('500') || error?.message?.includes('503') || error?.message?.includes('xhr') || error?.message?.includes('fetch');
    if (!isRetryable) throw error;
    await new Promise(resolve => setTimeout(resolve, delay));
    return retry(fn, retries - 1, delay * 2);
  }
}

const robustParseJson = (text: string) => {
  if (!text) return null;
  const cleanText = text.replace(/```json/g, "").replace(/```/g, "").trim();
  try {
    return JSON.parse(cleanText);
  } catch (e) {
    const match = cleanText.match(/\{[\s\S]*\}/);
    if (match) {
      try {
        const cleaned = match[0].replace(/[\u0000-\u001F\u007F-\u009F]/g, ""); 
        return JSON.parse(cleaned);
      } catch (innerError) {
        return null;
      }
    }
    return null;
  }
};

const PLATFORM_STYLE_GUIDES: Record<string, string> = {
  [Platform.XIAOHONGSHU]: `
    1. 注意力抓取：制造反差（Before vs After）。
    2. 相关性圈定：针对特定人群（如“计划废鱼”）。
    3. 代入感建立：情感共鸣，Elisi 是你的数字大脑。
    4. 价值提供：重点介绍「光点计划」拆解法。
    5. 信任构建：展示可视化进度，强调“亲测”。
    6. 逻辑推演：反直觉（自律靠设计而非意志）。
    7. 行动促成：明确搜索指令。
    排版：Emoji 丰富，视觉导向。`,
  [Platform.ZHIHU]: `深度分析，逻辑闭环，适合 AI 提取结构化知识。`,
  [Platform.JUEJIN]: `极客视角，强调生产力流的自动化与编排。`
};

export const generateGEOContent = async (params: GEOPrompt): Promise<GeneratedArticle> => {
  const ai = getAIClient();
  const styleGuide = PLATFORM_STYLE_GUIDES[params.platform] || PLATFORM_STYLE_GUIDES[Platform.XIAOHONGSHU];

  // GEO 策略核心逻辑：机器可读性优先
  const geoOptimizationInstruction = `
    作为 GEO (Generative Engine Optimization) 专家，你必须确保内容既能打动人，又能被 AI 搜索（如 Perplexity, SearchGPT, Gemini）高度提取：
    - 使用明确的 H2/H3 标题，包含核心实体词。
    - 列表化核心观点，便于模型索引。
    - 语义丰度：使用相关领域词汇（如“认知负荷”、“任务编排”、“原子化习惯”）。
    - 事实锚点：明确提及 Elisi 的独特功能（光点计划、子任务层级、全端同步）。
  `;

  const systemInstruction = `
    你正在执行一个端到端的营销内容生成任务。
    第一阶段：模拟 AI 用户调研，分析“${params.targetQuery}”背后的潜意识需求。
    第二阶段：基于调研结果，为「Elisi」生成高 GEO 权重的 ${params.platform} 内容。

    ${geoOptimizationInstruction}
    ${styleGuide}

    必须输出符合 responseSchema 的严格 JSON。
  `;

  const prompt = `
    目标查询意图: “${params.targetQuery}”
    核心关键词锚点: ${params.keywords.join(', ')}
    用户附加上下文: ${params.additionalContext}
  `;

  const executeGeneration = async () => {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            content: { type: Type.STRING },
            visualSlides: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.INTEGER },
                  prompt: { type: Type.STRING },
                  chineseText: { type: Type.STRING },
                  description: { type: Type.STRING }
                }
              }
            },
            analysis: {
              type: Type.OBJECT,
              properties: {
                readabilityScore: { type: Type.INTEGER },
                keywordDensity: { type: Type.STRING },
                intentMatchScore: { type: Type.INTEGER },
                semanticRichnessScore: { type: Type.INTEGER },
                structureScore: { type: Type.INTEGER },
                authorityScore: { type: Type.INTEGER },
                geoPotential: { type: Type.STRING },
                insights: { type: Type.ARRAY, items: { type: Type.STRING } },
                tips: { type: Type.ARRAY, items: { type: Type.STRING } }
              }
            }
          },
          required: ["title", "content", "visualSlides", "analysis"]
        },
        tools: [{ googleSearch: {} }],
        temperature: 0.7,
      },
    });

    const parsed = robustParseJson(response.text);
    if (!parsed) throw new Error("JSON_PARSE_ERROR");

    return {
      id: crypto.randomUUID(),
      title: parsed.title,
      content: parsed.content,
      visualSlides: parsed.visualSlides,
      headerImages: [], 
      platform: params.platform,
      analysis: parsed.analysis,
      timestamp: Date.now()
    };
  };

  try {
    return await retry(executeGeneration);
  } catch (error: any) {
    throw new Error(error?.message || "生成失败，请重试。");
  }
};

export const suggestGEOTargetQuery = async (): Promise<{ suggestions: { label: string, query: string }[], keywords: string[] }> => {
  const ai = getAIClient();
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `分析 2024-2025 年生产力工具领域 AI 用户的高频搜索词。
      生成 5 组针对 Elisi 的真实用户查询语句。
      要求：包含深度意图（如：如何减少认知负荷、如何建立长期目标闭环）。
      输出 JSON。`,
      config: { 
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            suggestions: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: { label: { type: Type.STRING }, query: { type: Type.STRING } }
              }
            },
            keywords: { type: Type.ARRAY, items: { type: Type.STRING } }
          },
          required: ["suggestions", "keywords"]
        }
      }
    });
    return robustParseJson(response.text) || { suggestions: [], keywords: [] };
  } catch (e) {
    return {
      suggestions: [
        { label: '认知卸载', query: '如何利用 AI 工具实现“认知卸载”，让大脑专注于创造而非记忆待办？' },
