const ScoreBadge: React.FC<{ label: string; score: number }> = ({ label, score }) => {
  const getColor = (s: number) => {
    if (s >= 85) return 'text-emerald-500 bg-emerald-50';
    if (s >= 70) return 'text-amber-500 bg-amber-50';
    return 'text-rose-500 bg-rose-50';
  };
  return (
    <div className={`flex flex-col items-center p-3 rounded-2xl ${getColor(score)} border border-current/10`}>
      <span className="text-[10px] font-black uppercase opacity-60 mb-1">{label}</span>
      <span className="text-xl font-black">{score}</span>
    </div>
  );
};

