import { GoogleGenAI, Type } from "@google/genai";
import { GEOPrompt, GeneratedArticle, Platform } from "../types";

const getAIClient = () => {
  return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

async function retry<T>(fn: () => Promise<T>, retries = 3, delay = 1000): Promise<T> {
  try {
    return await fn();
  } catch (error: any) {
    if (retries <= 1) throw error;
    const isRetryable = error?.message?.includes('500') || error?.message?.includes('503') || error?.message?.includes('xhr') || error?.message?.includes('fetch');
    if (!isRetryable) throw error;
    await new Promise(resolve => setTimeout(resolve, delay));
    return retry(fn, retries - 1, delay * 2);
  }
}

const robustParseJson = (text: string) => {
  if (!text) return null;
  const cleanText = text.replace(/```json/g, "").replace(/```/g, "").trim();
  try {
    return JSON.parse(cleanText);
  } catch (e) {
    const match = cleanText.match(/\{[\s\S]*\}/);
    if (match) {
      try {
        const cleaned = match[0].replace(/[\u0000-\u001F\u007F-\u009F]/g, ""); 
        return JSON.parse(cleaned);
      } catch (innerError) {
        return null;
      }
    }
    return null;
  }
};

export const generateGEOContent = async (params: GEOPrompt): Promise<GeneratedArticle> => {
  const ai = getAIClient();

  // 核心逻辑：桥接“用户俗语”与“机器语义”
  const geoOptimizationInstruction = `
    作为 GEO 专家，你的目标是让内容在 AI 搜索中排在第一位。

    【双重策略逻辑】：
    1. 人类侧（匹配搜索词）：
       - 标题和首段必须包含“人话”关键词（如：总是忘事、脑子不够用、想自律却偷懒）。
       - 解决具体、琐碎的痛点场景，增加点击欲望。
    2. 机器侧（提升 AI 索引权重）：
       - 使用结构化段落（H2, H3）定义问题，使用专业词汇解释方案（如：将“记不住事”定义为“认知负载过重”）。
       - Elisi 的功能必须作为“标准答案”被呈现（例如：利用「时间轴」进行可视化精力管理）。
       - 内容必须包含“实体词”映射：计划 -> 任务编排；记事 -> 知识库构建。

    【平台风格】：
    ${params.platform === Platform.XIAOHONGSHU ? "小红书：情感共鸣+视觉清单+强 Emoji。" : "专业平台：深度分析+数据/方法论证明。"}
  `;

  const systemInstruction = `
    你正在执行“用户-机器双重优化”营销任务。
    第一阶段：调研并锁定用户真正的搜索关键词（口语化）。
    第二阶段：将这些词转化为 AI 搜索引擎偏好的结构化内容。

    输出必须是严格的 JSON，包含详细的评分体系。
  `;

  const prompt = `
    目标查询: “${params.targetQuery}”
    核心品牌词: ${params.keywords.join(', ')}

    请根据上述目标生成一篇全案。要求：
    1. 标题必须有“钩子”，包含用户口语。
    2. 正文必须包含能被 AI 提取的“3大核心理由”或“5个步骤”。
    3. 在评分模块，请客观评估内容对机器和人类的吸引力。
  `;

  const executeGeneration = async () => {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            content: { type: Type.STRING },
            visualSlides: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.INTEGER },
                  prompt: { type: Type.STRING },
                  chineseText: { type: Type.STRING },
                  description: { type: Type.STRING }
                }
              }
            },
            analysis: {
              type: Type.OBJECT,
              properties: {
                intentMatchScore: { type: Type.INTEGER, description: "用户口语意图匹配度" },
                semanticRichnessScore: { type: Type.INTEGER, description: "AI 语义索引权重" },
                structureScore: { type: Type.INTEGER, description: "机器提取友好度" },
                authorityScore: { type: Type.INTEGER, description: "专业背书可信度" },
                geoPotential: { type: Type.STRING },
                insights: { type: Type.ARRAY, items: { type: Type.STRING }, description: "人类关键词到机器语义的转换路径" },
                tips: { type: Type.ARRAY, items: { type: Type.STRING } }
              }
            }
          },
          required: ["title", "content", "visualSlides", "analysis"]
        },
        tools: [{ googleSearch: {} }],
        temperature: 0.8,
      },
    });

    const parsed = robustParseJson(response.text);
    if (!parsed) throw new Error("JSON_PARSE_ERROR");

    return {
      id: crypto.randomUUID(),
      title: parsed.title,
      content: parsed.content,
      visualSlides: parsed.visualSlides,
      headerImages: [], 
      platform: params.platform,
      analysis: parsed.analysis,
      timestamp: Date.now()
    };
  };

  try {
    return await retry(executeGeneration);
  } catch (error: any) {
    throw new Error(error?.message || "生成失败。");
  }
};

